// ─── HESI A2 — 200 Questions | 8 Sections (Blueprint-matched) ───
const HESI_QUESTIONS = [
// ═══════════════════════════════════════════════
// MATH — 25 questions
// ═══════════════════════════════════════════════
{id:"hm1",exam:"HESI",section:"Math",q:"A nurse needs to give 0.5 g of a medication. The tablets available are 250 mg each. How many tablets should be given?",o:["A. 1","B. 1.5","C. 2","D. 2.5"],a:"C",e:"Convert: 0.5 g = 500 mg. 500 ÷ 250 = 2 tablets. Always verify dose-per-tablet before administering."},
{id:"hm2",exam:"HESI",section:"Math",q:"A patient requires an IV infusion of 1,200 mL over 10 hours. What is the hourly infusion rate?",o:["A. 100 mL/hr","B. 110 mL/hr","C. 120 mL/hr","D. 130 mL/hr"],a:"C",e:"1,200 ÷ 10 = 120 mL/hr. This is a standard IV rate calculation used in daily nursing practice."},
{id:"hm3",exam:"HESI",section:"Math",q:"Convert 3/8 to a decimal.",o:["A. 0.325","B. 0.375","C. 0.425","D. 0.475"],a:"B",e:"3 ÷ 8 = 0.375. Fraction-to-decimal conversions are tested frequently on the HESI math section."},
{id:"hm4",exam:"HESI",section:"Math",q:"A child weighs 44 lbs. What is their weight in kilograms?",o:["A. 18 kg","B. 20 kg","C. 22 kg","D. 24 kg"],a:"B",e:"44 ÷ 2.2 = 20 kg. Weight must always be converted to kg for most pediatric medication dosing."},
{id:"hm5",exam:"HESI",section:"Math",q:"Order: Amoxicillin 500 mg. Available: 250 mg/5 mL suspension. How many mL to administer?",o:["A. 5 mL","B. 8 mL","C. 10 mL","D. 12 mL"],a:"C",e:"Dose formula: (Desired ÷ Available) × Volume = (500 ÷ 250) × 5 = 2 × 5 = 10 mL."},
{id:"hm6",exam:"HESI",section:"Math",q:"What is 15% of 320?",o:["A. 42","B. 46","C. 48","D. 52"],a:"C",e:"15% × 320 = 0.15 × 320 = 48. Convert percent to decimal, then multiply."},
{id:"hm7",exam:"HESI",section:"Math",q:"A drip rate must be set for 750 mL over 6 hours using 20 gtt/mL tubing. What is the rate in gtt/min?",o:["A. 38 gtt/min","B. 40 gtt/min","C. 42 gtt/min","D. 45 gtt/min"],a:"C",e:"(750 × 20) ÷ (6 × 60) = 15,000 ÷ 360 = 41.67 ≈ 42 gtt/min."},
{id:"hm8",exam:"HESI",section:"Math",q:"Simplify: 2/3 + 3/4",o:["A. 5/7","B. 5/12","C. 17/12","D. 11/12"],a:"C",e:"LCD = 12. 8/12 + 9/12 = 17/12 (= 1 5/12). Always find the least common denominator."},
{id:"hm9",exam:"HESI",section:"Math",q:"A patient's urine output was 360 mL in 6 hours. What is the hourly output?",o:["A. 50 mL/hr","B. 55 mL/hr","C. 60 mL/hr","D. 65 mL/hr"],a:"C",e:"360 ÷ 6 = 60 mL/hr. Normal urine output is ≥30 mL/hr; 60 mL/hr is within normal range."},
{id:"hm10",exam:"HESI",section:"Math",q:"A medication requires 0.1 mg/kg. The patient weighs 70 kg. What dose is needed?",o:["A. 5 mg","B. 6 mg","C. 7 mg","D. 8 mg"],a:"C",e:"0.1 × 70 = 7 mg. Weight-based dosing is essential in nursing — always double-check units."},
{id:"hm11",exam:"HESI",section:"Math",q:"Express 0.625 as a fraction in lowest terms.",o:["A. 5/8","B. 6/9","C. 7/11","D. 3/5"],a:"A",e:"0.625 = 625/1000 = 5/8 when reduced. Verify: 5 ÷ 8 = 0.625 ✓"},
{id:"hm12",exam:"HESI",section:"Math",q:"If a nurse works 3 shifts of 12 hours and 2 shifts of 8 hours per week, what is the total weekly hours?",o:["A. 48 hrs","B. 50 hrs","C. 52 hrs","D. 56 hrs"],a:"C",e:"(3 × 12) + (2 × 8) = 36 + 16 = 52 hours per week."},
{id:"hm13",exam:"HESI",section:"Math",q:"Convert 1,500 mL to liters.",o:["A. 0.15 L","B. 1.5 L","C. 15 L","D. 150 L"],a:"B",e:"1,000 mL = 1 L. Therefore 1,500 mL ÷ 1,000 = 1.5 L. Unit conversion is fundamental in nursing."},
{id:"hm14",exam:"HESI",section:"Math",q:"A patient receives 2 tablets of 325 mg acetaminophen every 6 hours. What is the 24-hour total dose?",o:["A. 1,300 mg","B. 2,000 mg","C. 2,600 mg","D. 3,200 mg"],a:"C",e:"2 tablets × 325 mg = 650 mg per dose. 24 ÷ 6 = 4 doses/day. 650 × 4 = 2,600 mg. Max safe dose is 4,000 mg/day for adults."},
{id:"hm15",exam:"HESI",section:"Math",q:"Solve for x: 3x + 9 = 30",o:["A. x = 5","B. x = 7","C. x = 8","D. x = 9"],a:"B",e:"3x = 30 − 9 = 21. x = 21 ÷ 3 = 7."},
{id:"hm16",exam:"HESI",section:"Math",q:"What percent of 50 is 35?",o:["A. 60%","B. 65%","C. 70%","D. 75%"],a:"C",e:"(35 ÷ 50) × 100 = 0.70 × 100 = 70%."},
{id:"hm17",exam:"HESI",section:"Math",q:"A physician orders 40 mEq of potassium chloride to be added to 1 L of NS. The available vial contains 20 mEq/10 mL. How many mL of KCl to add?",o:["A. 10 mL","B. 15 mL","C. 20 mL","D. 25 mL"],a:"C",e:"Need 40 mEq. Available: 20 mEq/10 mL → 2 mEq/mL. 40 ÷ 2 = 20 mL. IV electrolyte math is critical for patient safety."},
{id:"hm18",exam:"HESI",section:"Math",q:"Convert 0130 military time to standard time.",o:["A. 1:30 PM","B. 11:30 AM","C. 1:30 AM","D. 12:30 AM"],a:"C",e:"Military time 0001–1259 = AM (as-is). 0130 = 1:30 AM. For PM hours, subtract 1200 from any time 1300–2359."},
{id:"hm19",exam:"HESI",section:"Math",q:"A patient's temperature is 101.3°F. Convert to Celsius. [C = (F − 32) × 5/9]",o:["A. 37.5°C","B. 38.0°C","C. 38.5°C","D. 39.0°C"],a:"C",e:"(101.3 − 32) × 5/9 = 69.3 × 5/9 = 346.5 ÷ 9 = 38.5°C."},
{id:"hm20",exam:"HESI",section:"Math",q:"The ratio of nurses to patients is 1:5. If there are 40 patients, how many nurses are needed?",o:["A. 6","B. 7","C. 8","D. 9"],a:"C",e:"40 ÷ 5 = 8 nurses. Safe nurse-to-patient ratios directly impact patient outcomes."},
{id:"hm21",exam:"HESI",section:"Math",q:"What is the median of: 4, 9, 2, 7, 5, 3, 6?",o:["A. 4","B. 5","C. 6","D. 7"],a:"B",e:"Ordered: 2, 3, 4, 5, 6, 7, 9. The middle value (4th of 7) = 5. Median is less affected by outliers than mean."},
{id:"hm22",exam:"HESI",section:"Math",q:"An IV solution has a concentration of 5 mg/mL. The order is for 35 mg. How many mL should be given?",o:["A. 5 mL","B. 7 mL","C. 9 mL","D. 10 mL"],a:"B",e:"35 mg ÷ 5 mg/mL = 7 mL. This basic concentration calculation is used in every clinical setting."},
{id:"hm23",exam:"HESI",section:"Math",q:"Multiply: 2.5 × 4.4",o:["A. 9.5","B. 10.0","C. 11.0","D. 11.5"],a:"C",e:"2.5 × 4.4 = 11.0. Decimal multiplication: multiply as integers (25 × 44 = 1100), then place decimal (2 places) = 11.00."},
{id:"hm24",exam:"HESI",section:"Math",q:"A nurse earns $26 per hour with time-and-a-half for overtime (>40 hrs). In a 48-hr week, what is her total pay?",o:["A. $1,196","B. $1,208","C. $1,196","D. $1,352"],a:"D",e:"Regular: 40 × $26 = $1,040. OT rate: $26 × 1.5 = $39. OT pay: 8 × $39 = $312. Total: $1,040 + $312 = $1,352."},
{id:"hm25",exam:"HESI",section:"Math",q:"What is 3/5 expressed as a percentage?",o:["A. 55%","B. 60%","C. 65%","D. 70%"],a:"B",e:"3 ÷ 5 = 0.60 = 60%. Fraction → decimal → percent: multiply decimal by 100."},

// ═══════════════════════════════════════════════
// READING — 25 questions
// ═══════════════════════════════════════════════
{id:"hr1",exam:"HESI",section:"Reading",q:"'The patient was diaphoretic and pallid upon assessment.' What does DIAPHORETIC mean?",o:["A. Confused","B. Pale","C. Profusely sweating","D. Short of breath"],a:"C",e:"Diaphoretic = profusely sweating. Pallid = pale. Combined, these suggest poor perfusion or shock."},
{id:"hr2",exam:"HESI",section:"Reading",q:"A passage states: 'Although fatigued, the nurse completed all patient assessments.' The word ALTHOUGH signals:",o:["A. Cause and effect","B. Time sequence","C. Contrast","D. Definition"],a:"C",e:"'Although' = contrast word. Despite fatigue (one condition), she completed the task (contrasting outcome). Other contrast words: however, yet, despite."},
{id:"hr3",exam:"HESI",section:"Reading",q:"'Contraindicated' most nearly means:",o:["A. Recommended","B. Required","C. Not advisable due to potential harm","D. Under investigation"],a:"C",e:"Contraindicated = a drug or treatment that should NOT be used in a specific situation because it may cause harm. Critical nursing vocabulary."},
{id:"hr4",exam:"HESI",section:"Reading",q:"Which type of evidence is MOST objective?",o:["A. A nurse's personal experience","B. A patient testimonial","C. A peer-reviewed randomized controlled trial","D. A physician's clinical opinion"],a:"C",e:"Randomized controlled trials (RCTs) are the gold standard of evidence — highest level of evidence-based practice due to controlled design and reproducibility."},
{id:"hr5",exam:"HESI",section:"Reading",q:"The prefix PRE- most likely means:",o:["A. After","B. Before","C. Against","D. Without"],a:"B",e:"Pre- = before. Preoperative = before surgery. Prenatal = before birth. Post- = after. Anti- = against. A- = without."},
{id:"hr6",exam:"HESI",section:"Reading",q:"'Ambulate 50 feet by post-op day 2.' This goal is best described as:",o:["A. A nursing diagnosis","B. A medical order","C. A measurable patient outcome","D. A safety risk"],a:"C",e:"SMART goals (Specific, Measurable, Achievable, Relevant, Time-bound) are measurable outcomes. This goal is specific (50 feet), time-bound (day 2)."},
{id:"hr7",exam:"HESI",section:"Reading",q:"'Exacerbation' most nearly means:",o:["A. Resolution","B. Stabilization","C. Improvement","D. Worsening"],a:"D",e:"Exacerbation = a flare-up or worsening of a condition. Common in chronic diseases: COPD exacerbation, asthma exacerbation, CHF exacerbation."},
{id:"hr8",exam:"HESI",section:"Reading",q:"An inference is BEST defined as:",o:["A. A directly stated fact","B. A conclusion drawn from available evidence","C. An author's stated opinion","D. A textbook definition"],a:"B",e:"Inference = logical conclusion derived from evidence not directly stated. Reading 'between the lines' using context clues and prior knowledge."},
{id:"hr9",exam:"HESI",section:"Reading",q:"Which sentence expresses an OPINION?",o:["A. The hospital opened in 1998","B. Nurses represent the largest healthcare workforce group","C. Nursing is the most rewarding profession in healthcare","D. The HESI exam has 8 possible test sections"],a:"C",e:"'Most rewarding' is a value judgment — it cannot be objectively verified. Opinions use words like best, worst, most, should, I believe."},
{id:"hr10",exam:"HESI",section:"Reading",q:"'Prophylactic antibiotics were administered before surgery.' PROPHYLACTIC means:",o:["A. Curative","B. Preventive","C. Therapeutic","D. Palliative"],a:"B",e:"Prophylactic = preventive. Given before a problem occurs to reduce risk. Example: pre-surgery antibiotics to prevent surgical site infection."},
{id:"hr11",exam:"HESI",section:"Reading",q:"The MAIN PURPOSE of nursing documentation is to:",o:["A. Protect nurses from legal liability only","B. Satisfy hospital administrative requirements","C. Ensure continuity and coordination of patient care","D. Provide billing information to insurance companies"],a:"C",e:"Primary purpose of documentation = continuity of care. All providers can access patient status, treatments given, and plan of care. Legal protection is a secondary benefit."},
{id:"hr12",exam:"HESI",section:"Reading",q:"'Patients in the ICU require 1:1 or 1:2 nurse-to-patient ratios.' This is an example of a:",o:["A. Nursing opinion","B. Factual standard of care","C. Hospital policy suggestion","D. Personal observation"],a:"B",e:"Nurse-to-patient ratios in ICUs are established standards of care supported by research — objective, verifiable, not an opinion."},
{id:"hr13",exam:"HESI",section:"Reading",q:"'Despite three failed attempts, the IV was finally placed.' The word DESPITE signals:",o:["A. Addition","B. Cause","C. Contrast/concession","D. Sequence"],a:"C",e:"'Despite' = contrast/concession. Something happened (success) even though a contrary condition existed (three failures). Same function as 'although.'"},
{id:"hr14",exam:"HESI",section:"Reading",q:"A care plan says: 'Problem: Impaired skin integrity.' This is an example of a:",o:["A. Medical diagnosis","B. Physician order","C. Nursing diagnosis","D. Patient complaint"],a:"C",e:"Nursing diagnoses describe patient responses to health problems. 'Impaired skin integrity' is a standard NANDA nursing diagnosis — different from medical diagnoses."},
{id:"hr15",exam:"HESI",section:"Reading",q:"'Acute' versus 'chronic' — what is the primary difference?",o:["A. Acute is more serious; chronic is mild","B. Acute is sudden/short-term; chronic is long-lasting","C. Acute requires surgery; chronic requires medication","D. Acute affects children; chronic affects adults"],a:"B",e:"Acute = sudden onset, short duration (e.g., acute MI). Chronic = long-lasting, often lifelong (e.g., chronic hypertension). Severity varies for both."},
{id:"hr16",exam:"HESI",section:"Reading",q:"Which context clue helps define 'tachypnea' in: 'The patient was tachypneic, breathing at 28 breaths per minute'?",o:["A. 'patient'","B. '28 breaths per minute'","C. 'was'","D. 'breathing at'"],a:"B",e:"'28 breaths per minute' is the context clue. Normal breathing rate is 12–20/min — 28 is elevated, indicating tachypnea = rapid breathing."},
{id:"hr17",exam:"HESI",section:"Reading",q:"'Iatrogenic' complications are those caused by:",o:["A. Pre-existing patient conditions","B. Genetic factors","C. Medical treatment or healthcare providers","D. Environmental toxins"],a:"C",e:"Iatrogenic = caused by medical treatment or healthcare intervention. Examples: hospital-acquired infections, medication side effects, procedure complications."},
{id:"hr18",exam:"HESI",section:"Reading",q:"A passage states: 'Handwashing reduces HAIs by 40%.' This represents what type of support?",o:["A. Anecdote","B. Expert opinion","C. Statistical evidence","D. Case study"],a:"C",e:"Percentages and numerical data = statistical evidence. Strongest type of factual support — objective, reproducible, and quantifiable."},
{id:"hr19",exam:"HESI",section:"Reading",q:"Which word is a SYNONYM for 'benign'?",o:["A. Malignant","B. Severe","C. Harmless","D. Progressive"],a:"C",e:"Benign = harmless or not cancerous. Antonym = malignant (cancerous/harmful). Context matters: a benign tumor is noncancerous; a benign remark is harmless."},
{id:"hr20",exam:"HESI",section:"Reading",q:"'The patient's respiratory rate was 22/min.' This is BEST classified as:",o:["A. A subjective finding","B. An objective finding","C. A nursing diagnosis","D. A medical order"],a:"B",e:"Objective findings are measurable/observable: vital signs, lab values, physical exam findings. Subjective = what the patient reports (pain, nausea). RR = objective."},
{id:"hr21",exam:"HESI",section:"Reading",q:"'Palliative care aims to relieve suffering rather than cure disease.' PALLIATIVE most nearly means:",o:["A. Curative","B. Preventive","C. Comfort-focused","D. Surgical"],a:"C",e:"Palliative = focused on comfort, quality of life, and symptom relief — not cure. Important in hospice and end-of-life care. Your background makes this one real."},
{id:"hr22",exam:"HESI",section:"Reading",q:"The author uses the word 'however' in mid-sentence. This signals a:",o:["A. Cause-and-effect relationship","B. Sequence of events","C. Contrast or shift in idea","D. Definition or example"],a:"C",e:"'However' is a contrast transition word. It signals the writer is about to present an opposing idea or exception. Other contrast words: but, yet, nevertheless, on the other hand."},
{id:"hr23",exam:"HESI",section:"Reading",q:"Which part of the nursing process involves collecting patient information?",o:["A. Planning","B. Implementation","C. Assessment","D. Evaluation"],a:"C",e:"Nursing process = ADPIE: Assessment (collect data), Diagnosis, Planning, Implementation (carry out plan), Evaluation (did it work?)."},
{id:"hr24",exam:"HESI",section:"Reading",q:"'The patient was lethargic and difficult to arouse.' LETHARGIC most nearly means:",o:["A. Agitated and restless","B. Abnormally drowsy and sluggish","C. Confused and disoriented","D. Unresponsive to all stimuli"],a:"B",e:"Lethargic = abnormally drowsy but arousable with stimulation. Different from stupor (arousable only with strong stimuli) or coma (unarousable)."},
{id:"hr25",exam:"HESI",section:"Reading",q:"Evidence-based practice (EBP) integrates which THREE components?",o:["A. Hospital policy, patient preference, nursing experience","B. Best research evidence, clinical expertise, patient values","C. Physician orders, nursing diagnoses, lab results","D. Textbook knowledge, peer advice, case studies"],a:"B",e:"EBP = Best available research + Clinical expertise + Patient values/preferences. All three must be considered. Supersedes tradition and seniority."},

// ═══════════════════════════════════════════════
// VOCABULARY — 30 questions
// ═══════════════════════════════════════════════
{id:"hv1",exam:"HESI",section:"Vocabulary",q:"An ANALGESIC is a medication that:",o:["A. Reduces fever","B. Relieves pain","C. Prevents infection","D. Lowers blood pressure"],a:"B",e:"Analgesic = pain reliever. Roots: 'an-' (without) + 'algesia' (pain). Examples: acetaminophen, ibuprofen, morphine."},
{id:"hv2",exam:"HESI",section:"Vocabulary",q:"DYSPNEA refers to:",o:["A. Painful urination","B. Difficulty swallowing","C. Difficulty breathing","D. Abnormal heart rhythm"],a:"C",e:"Dys- (difficult/painful) + -pnea (breathing) = difficulty breathing. Apnea = no breathing. Tachypnea = fast breathing (>20/min in adults)."},
{id:"hv3",exam:"HESI",section:"Vocabulary",q:"The suffix -ITIS means:",o:["A. Surgical removal","B. Inflammation","C. Study of","D. Tumor"],a:"B",e:"-itis = inflammation. Appendicitis = inflamed appendix. Tonsillitis = inflamed tonsils. Gastritis = inflamed stomach lining."},
{id:"hv4",exam:"HESI",section:"Vocabulary",q:"TACHYCARDIA is defined as:",o:["A. Heart rate < 60 bpm","B. Irregular heart rhythm","C. Heart rate > 100 bpm","D. Absent pulse"],a:"C",e:"Tachy- (fast) + -cardia (heart). Tachycardia = HR >100 bpm. Bradycardia = HR <60 bpm. Both can indicate serious cardiac conditions."},
{id:"hv5",exam:"HESI",section:"Vocabulary",q:"EDEMA is BEST defined as:",o:["A. Decreased blood flow","B. Abnormal fluid accumulation in tissues","C. Elevated blood pressure","D. Increased white blood cells"],a:"B",e:"Edema = swelling from fluid buildup in interstitial spaces. Causes: heart failure, kidney disease, inflammation, venous insufficiency."},
{id:"hv6",exam:"HESI",section:"Vocabulary",q:"The prefix HYPO- means:",o:["A. Above normal","B. Below normal","C. Both sides","D. Without"],a:"B",e:"Hypo- = below/under. Hypoglycemia = low blood sugar. Hypotension = low BP. Hyper- = above/over. These prefixes appear constantly in nursing."},
{id:"hv7",exam:"HESI",section:"Vocabulary",q:"PATHOGENIC means:",o:["A. Causing disease","B. Treating disease","C. Preventing disease","D. Studying disease"],a:"A",e:"Patho- (disease) + -genic (producing/causing) = disease-causing. Pathogens = bacteria, viruses, fungi that cause illness."},
{id:"hv8",exam:"HESI",section:"Vocabulary",q:"What does the suffix -ECTOMY mean?",o:["A. Inflammation of","B. Surgical incision into","C. Surgical removal of","D. Disease of"],a:"C",e:"-ectomy = surgical removal. Appendectomy = remove appendix. Mastectomy = remove breast. -otomy = incision (not removal). -ostomy = opening."},
{id:"hv9",exam:"HESI",section:"Vocabulary",q:"PROGNOSIS refers to:",o:["A. The cause of a disease","B. The predicted outcome of a disease","C. The treatment plan","D. The patient's chief complaint"],a:"B",e:"Prognosis = expected course and outcome of a disease. 'Good prognosis' = likely recovery. Different from diagnosis (identifying the disease)."},
{id:"hv10",exam:"HESI",section:"Vocabulary",q:"HEMATURIA means:",o:["A. Blood in the urine","B. Blood in the stool","C. Blood in vomit","D. Low red blood cell count"],a:"A",e:"Hemato- (blood) + -uria (urine condition) = blood in urine. Melena = blood in stool. Hematemesis = blood in vomit."},
{id:"hv11",exam:"HESI",section:"Vocabulary",q:"EMESIS means:",o:["A. Difficulty swallowing","B. Vomiting","C. Nausea","D. Bowel movement"],a:"B",e:"Emesis = vomiting. Antiemetics = drugs that prevent vomiting (e.g., ondansetron/Zofran). Nausea = urge to vomit but not the act itself."},
{id:"hv12",exam:"HESI",section:"Vocabulary",q:"The prefix BRADY- means:",o:["A. Fast","B. Slow","C. Painful","D. Abnormal"],a:"B",e:"Brady- = slow. Bradycardia = slow heart rate (<60 bpm). Bradypnea = slow breathing (<12 breaths/min). Tachy- = fast."},
{id:"hv13",exam:"HESI",section:"Vocabulary",q:"EPISTAXIS refers to:",o:["A. A nosebleed","B. A seizure","C. A skin rash","D. A cough"],a:"A",e:"Epistaxis = nosebleed. Medical terminology uses Greek/Latin roots — 'epi-' (upon) + '-staxis' (dripping). Common in hypertension and dry environments."},
{id:"hv14",exam:"HESI",section:"Vocabulary",q:"SYNCOPE means:",o:["A. Irregular heartbeat","B. Fainting or loss of consciousness","C. Muscle spasm","D. Sudden severe headache"],a:"B",e:"Syncope = fainting — temporary loss of consciousness due to decreased cerebral blood flow. Vasovagal syncope is the most common type."},
{id:"hv15",exam:"HESI",section:"Vocabulary",q:"BILATERAL means:",o:["A. Involving one side of the body","B. Involving both sides of the body","C. Below the waist","D. Involving internal organs"],a:"B",e:"Bi- (two) + lateral (sides) = affecting both sides. Bilateral leg edema = swelling in both legs. Unilateral = one side only."},
{id:"hv16",exam:"HESI",section:"Vocabulary",q:"The suffix -PHAGIA means:",o:["A. Speaking","B. Eating or swallowing","C. Breathing","D. Urinating"],a:"B",e:"-phagia = eating/swallowing. Dysphagia = difficulty swallowing. Polyphagia = excessive eating (seen in diabetes). Aphagia = inability to swallow."},
{id:"hv17",exam:"HESI",section:"Vocabulary",q:"AFEBRILE means:",o:["A. Having a high fever","B. Having a low-grade fever","C. Without fever","D. Having chills"],a:"C",e:"A- (without) + febrile (fever) = without fever. Febrile = having a fever (temp >100.4°F or 38°C). 'Patient is afebrile' = no fever present."},
{id:"hv18",exam:"HESI",section:"Vocabulary",q:"DIURETIC refers to a substance that:",o:["A. Increases blood pressure","B. Increases urine output","C. Decreases heart rate","D. Dilates blood vessels"],a:"B",e:"Diuretics increase urine production and excretion. Used to treat edema, hypertension, and heart failure. Examples: furosemide (Lasix), hydrochlorothiazide."},
{id:"hv19",exam:"HESI",section:"Vocabulary",q:"The suffix -OLOGY means:",o:["A. Surgical removal","B. Disease of","C. Study of","D. Condition of"],a:"C",e:"-ology = study of. Cardiology = study of the heart. Nephrology = study of kidneys. Oncology = study of cancer. -ologist = specialist in that field."},
{id:"hv20",exam:"HESI",section:"Vocabulary",q:"CYANOSIS refers to:",o:["A. Skin yellowing due to bilirubin","B. Skin reddening due to inflammation","C. Bluish discoloration due to poor oxygenation","D. Skin paleness due to anemia"],a:"C",e:"Cyanosis = blue/gray discoloration of skin/mucous membranes from decreased O2 saturation. Check lips, fingertips, nail beds. Jaundice = yellow (liver). Pallor = pale (anemia)."},
{id:"hv21",exam:"HESI",section:"Vocabulary",q:"SUBCUTANEOUS means:",o:["A. Into a vein","B. Into a muscle","C. Under the skin","D. Into a joint"],a:"C",e:"Sub- (under) + cutaneous (skin) = under the skin. Subcutaneous injections (SQ/SC) deposit medication into fatty tissue layer (e.g., insulin, heparin)."},
{id:"hv22",exam:"HESI",section:"Vocabulary",q:"PALPITATION refers to:",o:["A. Abnormal lung sounds","B. Awareness of an abnormal heartbeat","C. Pain upon palpation","D. Rapid breathing"],a:"B",e:"Palpitations = an uncomfortable awareness of one's own heartbeat — fluttering, pounding, or racing. May indicate arrhythmia or anxiety."},
{id:"hv23",exam:"HESI",section:"Vocabulary",q:"The word ABRASION means:",o:["A. A puncture wound","B. A deep surgical incision","C. A superficial scraping of skin","D. A bruise under the skin"],a:"C",e:"Abrasion = scrape that removes the outer skin layer (epidermis). Laceration = jagged tear. Puncture = deep, narrow wound. Contusion = bruise."},
{id:"hv24",exam:"HESI",section:"Vocabulary",q:"OLIGURIA refers to:",o:["A. Excessive urine output","B. Absence of urine","C. Painful urination","D. Decreased urine output"],a:"D",e:"Oliguria = urine output <400 mL/24 hours (or <30 mL/hr). Anuria = no urine. Polyuria = excessive urine. Oliguria signals possible renal failure or dehydration."},
{id:"hv25",exam:"HESI",section:"Vocabulary",q:"ANTIPYRETIC refers to a medication that:",o:["A. Prevents infection","B. Relieves pain","C. Reduces fever","D. Decreases inflammation only"],a:"C",e:"Antipyretic = fever reducer. Anti- (against) + pyretic (fever). Examples: acetaminophen (Tylenol), ibuprofen (Advil). Some drugs are both analgesic and antipyretic."},
{id:"hv26",exam:"HESI",section:"Vocabulary",q:"HEMOSTASIS means:",o:["A. The production of red blood cells","B. The process of stopping bleeding","C. Normal blood flow through vessels","D. Blood pressure regulation"],a:"B",e:"Hemo- (blood) + stasis (stopping) = stopping blood loss. Phases: vascular spasm → platelet plug → coagulation cascade. Critical in wound care and surgery."},
{id:"hv27",exam:"HESI",section:"Vocabulary",q:"The prefix PERI- means:",o:["A. Before","B. After","C. Around/surrounding","D. Below"],a:"C",e:"Peri- = around/surrounding. Pericardium = sac surrounding the heart. Perioperative = around the time of surgery. Peripheral = away from center."},
{id:"hv28",exam:"HESI",section:"Vocabulary",q:"NOCTURIA refers to:",o:["A. Nighttime confusion","B. Frequent urination during the night","C. Inability to sleep","D. Nighttime fever"],a:"B",e:"Noct- (night) + -uria (urine) = urinating at night, requiring waking from sleep. Common in BPH, diabetes, heart failure, and UTI."},
{id:"hv29",exam:"HESI",section:"Vocabulary",q:"SEPTICEMIA refers to:",o:["A. Inflammation of the lungs","B. Bacterial infection of the bloodstream","C. Blood clot in a vessel","D. Allergic reaction to medication"],a:"B",e:"Septicemia (also called bacteremia/sepsis) = bacteria in the bloodstream. Life-threatening emergency requiring immediate IV antibiotics and supportive care."},
{id:"hv30",exam:"HESI",section:"Vocabulary",q:"DYSPHAGIA means:",o:["A. Difficulty breathing","B. Difficulty speaking","C. Difficulty swallowing","D. Difficulty urinating"],a:"C",e:"Dys- (difficult) + -phagia (swallowing) = difficulty swallowing. Risk for aspiration — requires swallowing evaluation, positioning, and possibly modified diet."},

// ═══════════════════════════════════════════════
// GRAMMAR — 25 questions
// ═══════════════════════════════════════════════
{id:"hg1",exam:"HESI",section:"Grammar",q:"Which sentence is grammatically CORRECT?",o:["A. The nurse and the doctor was reviewing the chart","B. The nurse and the doctor were reviewing the chart","C. The nurse and the doctor is reviewing the chart","D. The nurse and the doctor has reviewed the chart"],a:"B",e:"Compound subjects joined by 'and' take a plural verb. 'The nurse and the doctor' = plural subject → 'were' (not was/is/has)."},
{id:"hg2",exam:"HESI",section:"Grammar",q:"Identify the OBJECT in: 'The physician prescribed the medication.'",o:["A. physician","B. prescribed","C. medication","D. The"],a:"C",e:"Subject = physician (who acts). Verb = prescribed (action). Object = medication (what receives the action). Subject → verb → object is the basic sentence structure."},
{id:"hg3",exam:"HESI",section:"Grammar",q:"Which option uses an apostrophe CORRECTLY?",o:["A. The nurses station is on the left","B. The nurses' station is on the left (multiple nurses)","C. The nurse's are working tonight","D. The nurse's station are clean"],a:"B",e:"nurses' = plural possessive (station belonging to multiple nurses). For plural nouns ending in 's,' add apostrophe after the s. For singular possessive: nurse's."},
{id:"hg4",exam:"HESI",section:"Grammar",q:"Choose the CORRECT pronoun: 'Between you and ___, the documentation was incomplete.'",o:["A. I","B. me","C. myself","D. mine"],a:"B",e:"Prepositions (between, for, to, with) require object pronouns: me, him, her, us, them. NOT subject pronouns (I, he, she). Test: 'between I' sounds wrong; 'between me' is correct."},
{id:"hg5",exam:"HESI",section:"Grammar",q:"Which sentence contains a dangling modifier?",o:["A. Walking down the hall, the nurse heard the alarm","B. Walking down the hall, the alarm was loud","C. The nurse, walking down the hall, heard the alarm","D. The nurse walked down the hall and heard the alarm"],a:"B",e:"Dangling modifier: 'Walking down the hall' must logically describe a person. But the sentence says the alarm was walking. The subject must perform the modifier's action."},
{id:"hg6",exam:"HESI",section:"Grammar",q:"Which word is spelled CORRECTLY?",o:["A. Accomodate","B. Occurance","C. Necessary","D. Recieve"],a:"C",e:"Necessary: one 'c,' two 's.' Memory aid: one Collar, two Socks. Accommodate (two c's, two m's). Occurrence (two c's, two r's). Receive (i before e except after c)."},
{id:"hg7",exam:"HESI",section:"Grammar",q:"'The patient complained of nausea; the nurse administered an antiemetic.' The semicolon here:",o:["A. Joins two unrelated sentences","B. Joins two related independent clauses","C. Introduces a list","D. Replaces a comma before 'and'"],a:"B",e:"Semicolons join two complete, related independent clauses without a conjunction. Both clauses here have subject + verb and are closely related in meaning."},
{id:"hg8",exam:"HESI",section:"Grammar",q:"Identify the ADVERB in: 'The nurse quickly administered the medication.'",o:["A. nurse","B. quickly","C. medication","D. administered"],a:"B",e:"Adverbs modify verbs, adjectives, or other adverbs. 'Quickly' modifies the verb 'administered.' Adverbs often end in -ly and answer how, when, where, or to what degree."},
{id:"hg9",exam:"HESI",section:"Grammar",q:"Which sentence uses a COMMA correctly?",o:["A. The doctor ordered labs, but, the results were delayed","B. The patient was stable, and the nurse documented the findings","C. After surgery the patient, was transferred to ICU","D. Medication was given, to reduce the fever"],a:"B",e:"Use a comma before a coordinating conjunction (FANBOYS: for, and, nor, but, or, yet, so) that joins two independent clauses. Option B has two complete clauses joined by 'and.'"},
{id:"hg10",exam:"HESI",section:"Grammar",q:"'Each of the nurses ___ responsible for documenting her own assessments.'",o:["A. are","B. were","C. is","D. have been"],a:"C",e:"'Each' is an indefinite singular pronoun → singular verb 'is.' Don't be misled by 'nurses' (plural). The subject is 'Each,' not 'nurses.'"},
{id:"hg11",exam:"HESI",section:"Grammar",q:"Which word is a CONJUNCTION?",o:["A. Quickly","B. Because","C. Hospital","D. Carefully"],a:"B",e:"Conjunctions connect words, phrases, or clauses. 'Because' is a subordinating conjunction. FANBOYS = coordinating conjunctions. 'Quickly/carefully' = adverbs."},
{id:"hg12",exam:"HESI",section:"Grammar",q:"'The patient, who was admitted yesterday, improved significantly.' The clause 'who was admitted yesterday' is:",o:["A. An independent clause","B. A prepositional phrase","C. A nonrestrictive relative clause","D. A dependent adverbial clause"],a:"C",e:"A nonrestrictive (nonessential) clause adds extra information but doesn't change the core meaning. It's set off with commas. Remove it: 'The patient improved significantly' — still complete."},
{id:"hg13",exam:"HESI",section:"Grammar",q:"Which of the following is a COMPLETE sentence?",o:["A. When the patient arrived at the unit.","B. Although the nurse was experienced.","C. The medication was administered on time.","D. Running to the code blue."],a:"C",e:"A complete sentence needs subject + verb and must express a complete thought. A and B are subordinate clauses (fragments). D lacks a subject. C = 'medication' (subject) + 'was administered' (verb)."},
{id:"hg14",exam:"HESI",section:"Grammar",q:"Identify the SUBJECT in: 'Under the patient's bed sat his shoes.'",o:["A. Under","B. bed","C. shoes","D. sat"],a:"C",e:"In inverted sentences, the verb comes before the subject. Rearrange: 'His shoes sat under the patient's bed.' Shoes = subject; sat = verb."},
{id:"hg15",exam:"HESI",section:"Grammar",q:"'The report had already been completed when the supervisor arrived.' Which tense is 'had been completed'?",o:["A. Simple past","B. Past progressive","C. Past perfect","D. Future perfect"],a:"C",e:"Past perfect = had + past participle. Used for an action completed BEFORE another past action. The report was done BEFORE the supervisor arrived — past perfect is correct."},
{id:"hg16",exam:"HESI",section:"Grammar",q:"Which of the following is CORRECTLY capitalized?",o:["A. The patient was admitted to the Emergency room","B. The Patient was admitted to the emergency room","C. The patient was admitted to the emergency room","D. the patient was admitted to the Emergency Room"],a:"C",e:"Capitalize proper nouns and the first word of a sentence. 'Emergency room' is a common noun (not a proper name) — lowercase. 'The' starts the sentence — capitalize."},
{id:"hg17",exam:"HESI",section:"Grammar",q:"Which sentence is PASSIVE voice?",o:["A. The nurse administered the medication","B. The medication was administered by the nurse","C. The nurse quickly gave the drug","D. After checking the MAR, the nurse gave the medication"],a:"B",e:"Passive voice: subject receives the action. 'The medication' (subject) received the action 'was administered.' Active: 'The nurse administered the medication.' Nursing documentation should use active voice when possible."},
{id:"hg18",exam:"HESI",section:"Grammar",q:"'The doctor asked the nurse to chart the findings.' 'To chart' is a(n):",o:["A. Gerund","B. Infinitive","C. Participle","D. Auxiliary verb"],a:"B",e:"Infinitive = to + base verb (to chart, to run, to assess). Gerund = verb + -ing used as noun (charting is important). Participle = verb form used as adjective."},
{id:"hg19",exam:"HESI",section:"Grammar",q:"Which sentence contains a MISPLACED modifier?",o:["A. The nurse gave the patient her discharge papers","B. Wrapped in gauze, the nurse changed the wound dressing","C. The attending physician reviewed the lab results carefully","D. The night shift nurse documented the findings"],a:"B",e:"'Wrapped in gauze' should modify the wound dressing, not the nurse. Misplaced: 'the nurse' appears to be wrapped in gauze. Correct: 'The nurse changed the wound dressing, which was wrapped in gauze.'"},
{id:"hg20",exam:"HESI",section:"Grammar",q:"Which sentence uses CORRECT subject-verb agreement?",o:["A. The team of nurses are meeting tonight","B. Neither the doctor nor the nurses was available","C. The list of medications were updated","D. The team of nurses is meeting tonight"],a:"D",e:"Collective nouns (team, staff, group) take singular verbs when acting as a unit. 'The team… is.' For 'neither/nor': verb agrees with the nearest subject — 'nurses were.'"},
{id:"hg21",exam:"HESI",section:"Grammar",q:"Choose the correct form: 'The patient's condition is ___ than it was yesterday.'",o:["A. more worse","B. worser","C. worst","D. worse"],a:"D",e:"Comparative adjective (comparing two things) = -er form: worse (not 'more worse' — double comparison error). Superlative (three or more) = -est: worst."},
{id:"hg22",exam:"HESI",section:"Grammar",q:"Which word is a PREPOSITION?",o:["A. Carefully","B. Running","C. Between","D. Administer"],a:"C",e:"Prepositions show relationships between nouns/pronouns and other words: between, at, in, on, under, over, through, with, by. 'Between the nurses' stations.'"},
{id:"hg23",exam:"HESI",section:"Grammar",q:"'The nurse who was on call last night is exhausted.' This sentence contains:",o:["A. A compound sentence","B. A simple sentence with a relative clause","C. A compound-complex sentence","D. Two independent clauses"],a:"B",e:"One independent clause: 'The nurse is exhausted.' The relative clause 'who was on call last night' modifies 'nurse' and depends on it — it's not independent."},
{id:"hg24",exam:"HESI",section:"Grammar",q:"Which option correctly uses quotation marks?",o:["A. The patient said she was \"fine\"","B. The physician stated, \"The patient needs surgery.\"","C. The nurse documented \"pain 8/10\"","D. The form stated patient refused \"treatment\""],a:"B",e:"Use quotation marks for direct speech (exact words spoken). A comma precedes the quoted speech. Period goes inside the quotation mark. Options A, C, D use quotes for emphasis — incorrect."},
{id:"hg25",exam:"HESI",section:"Grammar",q:"'The medication must be taken with food.' MUST indicates:",o:["A. Possibility","B. Preference","C. Obligation/necessity","D. Permission"],a:"C",e:"Modal verbs express attitude toward an action. Must = obligation/necessity (strongest). Should = recommendation. May = permission. Could/might = possibility."},

// ═══════════════════════════════════════════════
// BIOLOGY — 20 questions
// ═══════════════════════════════════════════════
{id:"hb1",exam:"HESI",section:"Biology",q:"What is the primary function of the mitochondria?",o:["A. Protein synthesis","B. ATP production (energy)","C. Cell division","D. DNA storage"],a:"B",e:"Mitochondria = 'powerhouse of the cell.' Produces ATP via aerobic cellular respiration. Cells with high energy demands (muscle, liver) have the most mitochondria."},
{id:"hb2",exam:"HESI",section:"Biology",q:"What type of cell division produces gametes (sex cells)?",o:["A. Mitosis","B. Binary fission","C. Meiosis","D. Cytokinesis"],a:"C",e:"Meiosis produces 4 haploid cells (23 chromosomes each) — sperm and eggs. Mitosis produces 2 identical diploid cells (46 chromosomes) for growth and repair."},
{id:"hb3",exam:"HESI",section:"Biology",q:"A cell placed in a hypertonic solution will:",o:["A. Swell and burst","B. Remain unchanged","C. Shrink as water moves out","D. Divide more rapidly"],a:"C",e:"Hypertonic = higher solute concentration outside. Water leaves the cell by osmosis → cell shrinks (crenation). Hypotonic = water enters cell → cell swells."},
{id:"hb4",exam:"HESI",section:"Biology",q:"Which organelle is responsible for protein synthesis?",o:["A. Golgi apparatus","B. Lysosome","C. Ribosome","D. Vacuole"],a:"C",e:"Ribosomes = protein synthesis factories. Found free in cytoplasm or attached to rough ER. mRNA is read at ribosomes to produce proteins."},
{id:"hb5",exam:"HESI",section:"Biology",q:"In Mendelian genetics, if both parents are carriers (Aa) for a recessive trait, what percent of offspring will be affected (aa)?",o:["A. 25%","B. 50%","C. 75%","D. 100%"],a:"A",e:"Aa × Aa Punnett square: AA (25%), Aa (50%), aa (25%). Only aa expresses the recessive trait = 25%. This applies to conditions like cystic fibrosis and sickle cell."},
{id:"hb6",exam:"HESI",section:"Biology",q:"Which base pairs with Adenine (A) in DNA?",o:["A. Guanine (G)","B. Cytosine (C)","C. Uracil (U)","D. Thymine (T)"],a:"D",e:"DNA base pairs: A-T and G-C. In RNA: A pairs with U (Uracil replaces Thymine). 'AT the GC meeting' — a memory device for base pairing rules."},
{id:"hb7",exam:"HESI",section:"Biology",q:"What is the function of the cell membrane?",o:["A. Produce ATP","B. Store genetic material","C. Regulate what enters and exits the cell","D. Synthesize proteins"],a:"C",e:"The cell membrane = selectively permeable barrier. Controls movement of substances in/out of cell via diffusion, osmosis, active transport, and endocytosis."},
{id:"hb8",exam:"HESI",section:"Biology",q:"Photosynthesis converts which inputs into glucose?",o:["A. O₂ and glucose into CO₂","B. CO₂ and H₂O into glucose using light energy","C. Glucose and O₂ into ATP","D. ATP and ADP into glucose"],a:"B",e:"Photosynthesis: 6CO₂ + 6H₂O + light energy → C₆H₁₂O₆ + 6O₂. Cellular respiration is the reverse. Plants are producers; humans are consumers."},
{id:"hb9",exam:"HESI",section:"Biology",q:"Which of the following is the correct hierarchy of biological organization from smallest to largest?",o:["A. Cell → tissue → organ → organ system → organism","B. Tissue → cell → organ → organism → organ system","C. Organ → tissue → cell → organism → organ system","D. Cell → organ → tissue → organ system → organism"],a:"A",e:"Order: Atom → Molecule → Organelle → Cell → Tissue → Organ → Organ System → Organism. Know this hierarchy — it appears in both HESI and nursing coursework."},
{id:"hb10",exam:"HESI",section:"Biology",q:"Aerobic cellular respiration requires which gas?",o:["A. Carbon dioxide","B. Nitrogen","C. Oxygen","D. Hydrogen"],a:"C",e:"Aerobic respiration: Glucose + O₂ → CO₂ + H₂O + ATP. Requires oxygen. Anaerobic respiration occurs without oxygen and produces lactic acid (less efficient)."},
{id:"hb11",exam:"HESI",section:"Biology",q:"Which type of RNA carries the genetic code from the nucleus to ribosomes?",o:["A. rRNA (ribosomal RNA)","B. tRNA (transfer RNA)","C. mRNA (messenger RNA)","D. siRNA (silencing RNA)"],a:"C",e:"mRNA = messenger — carries genetic code (from DNA in nucleus) to ribosomes for protein synthesis. rRNA makes up ribosome structure. tRNA brings amino acids."},
{id:"hb12",exam:"HESI",section:"Biology",q:"What is the role of lysosomes?",o:["A. Produce energy","B. Package proteins for export","C. Digest cellular waste and foreign particles","D. Regulate cell division"],a:"C",e:"Lysosomes = cellular 'garbage disposals.' Contain digestive enzymes that break down old organelles, bacteria, and debris. Dysfunction causes lysosomal storage diseases."},
{id:"hb13",exam:"HESI",section:"Biology",q:"The plasma membrane is described as 'fluid mosaic' because:",o:["A. It is solid and rigid","B. Phospholipids and proteins move laterally within the membrane","C. It dissolves in water","D. It contains no proteins"],a:"B",e:"Fluid mosaic model (Singer & Nicolson, 1972): phospholipid bilayer is fluid (lipids can move), and proteins are embedded like tiles in a mosaic."},
{id:"hb14",exam:"HESI",section:"Biology",q:"Which process moves molecules from LOW to HIGH concentration, requiring energy (ATP)?",o:["A. Simple diffusion","B. Osmosis","C. Facilitated diffusion","D. Active transport"],a:"D",e:"Active transport moves substances AGAINST their concentration gradient (low → high) and requires ATP energy. Example: sodium-potassium pump in nerve cells."},
{id:"hb15",exam:"HESI",section:"Biology",q:"The Golgi apparatus is responsible for:",o:["A. Producing ATP","B. Synthesizing DNA","C. Packaging and shipping proteins","D. Breaking down lipids"],a:"C",e:"Golgi apparatus = cellular 'post office.' Modifies, packages, and ships proteins to their final destinations (cell membrane, secretion, lysosomes)."},
{id:"hb16",exam:"HESI",section:"Biology",q:"In genetics, an organism that has two identical alleles for a trait is called:",o:["A. Heterozygous","B. Homozygous","C. Codominant","D. Recessive"],a:"B",e:"Homozygous = two identical alleles (AA or aa). Heterozygous = two different alleles (Aa). Dominant allele (A) masks recessive allele (a) when heterozygous."},
{id:"hb17",exam:"HESI",section:"Biology",q:"Enzymes function as:",o:["A. Energy sources","B. Biological catalysts that speed up reactions","C. Genetic material","D. Structural proteins"],a:"B",e:"Enzymes are biological catalysts — they lower activation energy to speed up chemical reactions without being consumed. Each enzyme is specific to its substrate."},
{id:"hb18",exam:"HESI",section:"Biology",q:"During mitosis, which phase involves the chromosomes aligning at the cell's midpoint?",o:["A. Prophase","B. Anaphase","C. Telophase","D. Metaphase"],a:"D",e:"PMAT: Prophase (condense), Metaphase (align at middle), Anaphase (apart to poles), Telophase (two nuclei form). 'Metaphase = Middle.'"},
{id:"hb19",exam:"HESI",section:"Biology",q:"What does the term 'homeostasis' mean?",o:["A. Cell division","B. The body's ability to maintain a stable internal environment","C. Genetic mutation","D. Protein synthesis"],a:"B",e:"Homeostasis = the body's ability to maintain internal stability despite external changes. Examples: regulating body temp (98.6°F), blood glucose, pH (7.35–7.45)."},
{id:"hb20",exam:"HESI",section:"Biology",q:"Which structure controls the cell's activities and contains DNA?",o:["A. Mitochondria","B. Ribosome","C. Cell membrane","D. Nucleus"],a:"D",e:"The nucleus = control center of the cell. Contains DNA (genetic blueprint), manages cell activities, and directs protein synthesis via mRNA transcription."},

// ═══════════════════════════════════════════════
// CHEMISTRY — 20 questions
// ═══════════════════════════════════════════════
{id:"hc1",exam:"HESI",section:"Chemistry",q:"What are the three subatomic particles of an atom?",o:["A. Neutron, electron, photon","B. Proton, neutron, electron","C. Proton, positron, neutron","D. Electron, quark, photon"],a:"B",e:"Protons (positive, nucleus), Neutrons (neutral, nucleus), Electrons (negative, orbitals). Atomic number = number of protons. Mass number = protons + neutrons."},
{id:"hc2",exam:"HESI",section:"Chemistry",q:"A solution with a pH of 3 is considered:",o:["A. Strongly basic","B. Neutral","C. Strongly acidic","D. Weakly basic"],a:"C",e:"pH 0–6 = acidic (lower = more acidic). pH 7 = neutral. pH 8–14 = basic. pH 3 = strongly acidic. Blood pH 7.35–7.45 = slightly basic."},
{id:"hc3",exam:"HESI",section:"Chemistry",q:"An IONIC bond forms when:",o:["A. Two atoms share electrons equally","B. One atom transfers electrons to another","C. Atoms share electrons unequally","D. Atoms repel each other"],a:"B",e:"Ionic bond = transfer of electrons from one atom (becomes cation +) to another (becomes anion −). Example: Na⁺ + Cl⁻ → NaCl (table salt)."},
{id:"hc4",exam:"HESI",section:"Chemistry",q:"What type of bond holds the two strands of DNA together?",o:["A. Ionic bonds","B. Covalent bonds","C. Hydrogen bonds","D. Metallic bonds"],a:"C",e:"Hydrogen bonds hold complementary DNA base pairs (A-T and G-C) together. These are relatively weak individually but strong in large numbers. Covalent bonds hold atoms within each strand."},
{id:"hc5",exam:"HESI",section:"Chemistry",q:"In the reaction: NaOH + HCl → NaCl + H₂O. This is an example of a:",o:["A. Synthesis reaction","B. Decomposition reaction","C. Neutralization reaction","D. Combustion reaction"],a:"C",e:"Acid + Base → Salt + Water = neutralization reaction. NaOH (base) + HCl (acid) → NaCl (salt) + H₂O. Relevant to the body's buffer systems."},
{id:"hc6",exam:"HESI",section:"Chemistry",q:"The atomic number of an element represents the number of:",o:["A. Neutrons in the nucleus","B. Electrons in the outer shell","C. Protons in the nucleus","D. Protons plus neutrons"],a:"C",e:"Atomic number = protons. This uniquely identifies each element on the periodic table. Atomic mass = protons + neutrons."},
{id:"hc7",exam:"HESI",section:"Chemistry",q:"Which statement BEST describes an ISOTOPE?",o:["A. An atom with a different number of electrons","B. An atom of the same element with a different number of neutrons","C. A different element with the same atomic mass","D. An ion with a positive charge"],a:"B",e:"Isotopes = same element (same protons), different neutron count → different atomic mass. Carbon-12 vs. Carbon-14. Radioactive isotopes used in medical imaging (Tc-99m)."},
{id:"hc8",exam:"HESI",section:"Chemistry",q:"Which type of chemical bond involves atoms sharing electrons?",o:["A. Ionic bond","B. Hydrogen bond","C. Covalent bond","D. Van der Waals bond"],a:"C",e:"Covalent bond = sharing of electron pairs between atoms. Can be single (share 1 pair), double (2 pairs), or triple (3 pairs). Most bonds in biological molecules are covalent."},
{id:"hc9",exam:"HESI",section:"Chemistry",q:"What is the molarity of a solution containing 2 moles of NaCl in 1 liter of water?",o:["A. 0.5 M","B. 1 M","C. 2 M","D. 4 M"],a:"C",e:"Molarity (M) = moles of solute ÷ liters of solution. 2 mol ÷ 1 L = 2 M. Used in IV solution calculations and lab chemistry."},
{id:"hc10",exam:"HESI",section:"Chemistry",q:"Water (H₂O) is considered a polar molecule because:",o:["A. It contains no charged particles","B. The oxygen end is slightly negative and hydrogen ends slightly positive","C. The two hydrogen atoms have equal electronegativity to oxygen","D. It has a linear molecular shape"],a:"B",e:"Oxygen is more electronegative than hydrogen → unequal electron sharing → partial charges. This polarity gives water its unique properties (surface tension, solvent ability)."},
{id:"hc11",exam:"HESI",section:"Chemistry",q:"Which statement about enzymes is TRUE?",o:["A. Enzymes are consumed in chemical reactions","B. Enzymes lower the activation energy of reactions","C. Enzymes change the final products of reactions","D. High temperatures always increase enzyme activity"],a:"B",e:"Enzymes = biological catalysts that lower activation energy. They are NOT consumed, do NOT change products, and are denatured (destroyed) by extreme temperatures or pH changes."},
{id:"hc12",exam:"HESI",section:"Chemistry",q:"What is the product of combining an acid and a base?",o:["A. Another acid","B. An anion and a cation only","C. Salt and water","D. Two new acids"],a:"C",e:"Acid + Base → Salt + Water (neutralization). Example: HCl + NaOH → NaCl + H₂O. Body buffers (bicarbonate system) work on this principle."},
{id:"hc13",exam:"HESI",section:"Chemistry",q:"Which element is the MOST abundant in the human body by mass?",o:["A. Carbon","B. Hydrogen","C. Nitrogen","D. Oxygen"],a:"D",e:"By mass: O (65%) > C (18%) > H (10%) > N (3%). Oxygen's abundance reflects its presence in water and all organic molecules. By number of atoms, hydrogen is most abundant."},
{id:"hc14",exam:"HESI",section:"Chemistry",q:"What is meant by a 'solute'?",o:["A. The substance that dissolves","B. The liquid in which something dissolves","C. The resulting solution","D. The concentration of a solution"],a:"A",e:"Solute = substance being dissolved. Solvent = substance doing the dissolving. Solution = solute + solvent. In NaCl solution: NaCl = solute; water = solvent."},
{id:"hc15",exam:"HESI",section:"Chemistry",q:"An EXOTHERMIC reaction:",o:["A. Absorbs energy from surroundings","B. Releases energy to surroundings","C. Has no energy change","D. Only occurs at high temperatures"],a:"B",e:"Exothermic = energy released (EXit = out). Combustion is exothermic. Endothermic = energy absorbed. Cellular respiration releases heat — that's why your body generates warmth."},
{id:"hc16",exam:"HESI",section:"Chemistry",q:"Which of the following is a property of ACIDS?",o:["A. Accepts protons (H⁺)","B. Tastes bitter","C. Donates protons (H⁺)","D. Turns red litmus paper blue"],a:"C",e:"Acids donate H⁺ (protons). Bases accept H⁺. Acids taste sour (not bitter — bases are bitter), turn blue litmus red, have pH < 7. Know your acid-base chemistry for ABG interpretation."},
{id:"hc17",exam:"HESI",section:"Chemistry",q:"What does a CATALYST do in a chemical reaction?",o:["A. Increases the temperature of the reaction","B. Is consumed to produce products","C. Speeds up the reaction without being consumed","D. Changes the final products"],a:"C",e:"Catalysts (enzymes in biology) lower activation energy and speed up reactions without being consumed. They can be reused. Inhibiting catalysts = slowing reactions."},
{id:"hc18",exam:"HESI",section:"Chemistry",q:"The periodic table organizes elements by:",o:["A. Alphabetical order","B. Increasing atomic mass only","C. Increasing atomic number and repeating properties","D. State of matter at room temperature"],a:"C",e:"Mendeleev's periodic table: elements arranged by increasing atomic number, with repeating (periodic) chemical properties in each column (group). Groups = similar properties; Periods = rows."},
{id:"hc19",exam:"HESI",section:"Chemistry",q:"Hydrogen peroxide (H₂O₂) breaks down to water and oxygen. This is a ___ reaction.",o:["A. Synthesis","B. Decomposition","C. Single replacement","D. Combustion"],a:"B",e:"Decomposition = one compound breaks into two or more simpler substances. H₂O₂ → H₂O + O₂. Catalase enzyme speeds this reaction in body tissues."},
{id:"hc20",exam:"HESI",section:"Chemistry",q:"A buffer solution resists changes in:",o:["A. Temperature","B. Volume","C. Concentration of solutes","D. pH"],a:"D",e:"Buffers resist pH changes by absorbing excess H⁺ or OH⁻. The body's main buffer: bicarbonate-carbonic acid system (HCO₃⁻/H₂CO₃). Critical for maintaining blood pH 7.35–7.45."},

// ═══════════════════════════════════════════════
// ANATOMY & PHYSIOLOGY — 30 questions
// ═══════════════════════════════════════════════
{id:"ha1",exam:"HESI",section:"A&P",q:"What is the PRIMARY function of the SA node?",o:["A. Receive oxygenated blood from lungs","B. Initiate each heartbeat as the natural pacemaker","C. Prevent backflow between ventricles","D. Regulate respiratory rate"],a:"B",e:"SA (sinoatrial) node in right atrium = natural pacemaker, fires 60–100 bpm. AV node delays impulse to allow ventricles to fill. Bundle of His → Purkinje fibers complete conduction."},
{id:"ha2",exam:"HESI",section:"A&P",q:"Oxygenated blood travels from the lungs to the heart via the:",o:["A. Pulmonary artery","B. Aorta","C. Pulmonary vein","D. Superior vena cava"],a:"C",e:"Pulmonary veins (4 total) carry O₂-rich blood from lungs → left atrium. Remember: veins = TO heart; arteries = FROM heart. Pulmonary artery carries deoxygenated blood TO lungs."},
{id:"ha3",exam:"HESI",section:"A&P",q:"Which organ produces both insulin and digestive enzymes?",o:["A. Liver","B. Adrenal gland","C. Pancreas","D. Thyroid"],a:"C",e:"Pancreas = dual function. Endocrine: islets of Langerhans produce insulin (beta cells) and glucagon (alpha cells). Exocrine: acinar cells produce digestive enzymes secreted into duodenum."},
{id:"ha4",exam:"HESI",section:"A&P",q:"Normal adult arterial blood pH range is:",o:["A. 7.25–7.30","B. 7.35–7.45","C. 7.50–7.60","D. 7.20–7.35"],a:"B",e:"Normal blood pH = 7.35–7.45 (slightly alkaline). Below 7.35 = acidosis; above 7.45 = alkalosis. Memorize for ABG interpretation — critical nursing skill."},
{id:"ha5",exam:"HESI",section:"A&P",q:"The mitral valve separates which chambers?",o:["A. Right atrium and right ventricle","B. Left atrium and left ventricle","C. Right ventricle and pulmonary artery","D. Left ventricle and aorta"],a:"B",e:"Mitral (bicuspid) valve = left side. Tricuspid = right side (3 cusps). Aortic valve = between left ventricle and aorta. Pulmonic valve = between right ventricle and pulmonary artery."},
{id:"ha6",exam:"HESI",section:"A&P",q:"Which part of the brainstem controls breathing and heart rate?",o:["A. Cerebellum","B. Pons","C. Medulla oblongata","D. Thalamus"],a:"C",e:"Medulla oblongata (lowest brainstem) = vital center for breathing, heart rate, BP, swallowing. Injury here = life-threatening. Cerebellum = balance/coordination. Thalamus = sensory relay."},
{id:"ha7",exam:"HESI",section:"A&P",q:"The functional unit of the kidney is the:",o:["A. Glomerulus","B. Nephron","C. Loop of Henle","D. Collecting duct"],a:"B",e:"The nephron is the functional unit of the kidney (~1 million per kidney). It includes: glomerulus (filter), Bowman's capsule, proximal tubule, loop of Henle, distal tubule, collecting duct."},
{id:"ha8",exam:"HESI",section:"A&P",q:"Which hormone is released by the adrenal cortex in response to long-term stress?",o:["A. Epinephrine","B. Insulin","C. Cortisol","D. Aldosterone"],a:"C",e:"Adrenal cortex = cortisol (stress response, anti-inflammatory) and aldosterone (Na retention). Adrenal medulla = epinephrine/norepinephrine (fight-or-flight). Cortisol is for sustained stress."},
{id:"ha9",exam:"HESI",section:"A&P",q:"Which substance carries oxygen in red blood cells?",o:["A. Albumin","B. Fibrinogen","C. Hemoglobin","D. Platelet factor"],a:"C",e:"Hemoglobin contains iron (heme group) that binds O₂ in lungs, releases it to tissues. Low hemoglobin = anemia → decreased O₂ carrying capacity → fatigue, pallor, tachycardia."},
{id:"ha10",exam:"HESI",section:"A&P",q:"The pharynx serves as a passageway for both:",o:["A. Blood and lymph","B. Air and food","C. Bile and digestive enzymes","D. Urine and blood"],a:"B",e:"Pharynx (throat) is shared by the respiratory (nasopharynx) and digestive (oropharynx/laryngopharynx) systems. The epiglottis prevents food from entering the trachea during swallowing."},
{id:"ha11",exam:"HESI",section:"A&P",q:"What type of muscle is found in the walls of the digestive tract?",o:["A. Skeletal","B. Cardiac","C. Smooth","D. Striated"],a:"C",e:"Smooth (visceral) muscle = involuntary, in walls of hollow organs (GI tract, bladder, blood vessels). Produces peristalsis. Cardiac = heart only. Skeletal = voluntary, attached to bones."},
{id:"ha12",exam:"HESI",section:"A&P",q:"Which hormone DECREASES blood glucose levels?",o:["A. Glucagon","B. Cortisol","C. Epinephrine","D. Insulin"],a:"D",e:"Insulin (beta cells) lowers blood glucose by facilitating glucose uptake into cells. Glucagon (alpha cells) raises glucose. Cortisol and epinephrine also raise glucose — stress hormones."},
{id:"ha13",exam:"HESI",section:"A&P",q:"The sinoatrial (SA) node is located in the:",o:["A. Left ventricle","B. Right atrium","C. Interventricular septum","D. Left atrium"],a:"B",e:"SA node is in the right atrium, near the opening of the superior vena cava. It generates the electrical impulse that starts each heartbeat."},
{id:"ha14",exam:"HESI",section:"A&P",q:"Gas exchange (O₂ and CO₂) in the lungs occurs in the:",o:["A. Bronchi","B. Trachea","C. Alveoli","D. Bronchioles"],a:"C",e:"Alveoli = tiny air sacs at the end of respiratory tree. Thin walls + surrounding capillaries = efficient gas exchange. O₂ diffuses into blood; CO₂ diffuses out to be exhaled."},
{id:"ha15",exam:"HESI",section:"A&P",q:"The vertebral column is divided into how many regions?",o:["A. 3","B. 4","C. 5","D. 6"],a:"C",e:"5 regions: Cervical (7 vertebrae, C1-C7), Thoracic (12, T1-T12), Lumbar (5, L1-L5), Sacral (5 fused), Coccygeal (4 fused). Total = 33 bones (26 functional units in adults)."},
{id:"ha16",exam:"HESI",section:"A&P",q:"The function of the lymphatic system includes all EXCEPT:",o:["A. Returning excess interstitial fluid to blood","B. Filtering pathogens through lymph nodes","C. Transporting dietary fats via lacteals","D. Producing red blood cells"],a:"D",e:"RBC production = bone marrow (hematopoiesis). Lymphatic system: returns fluid to blood, filters pathogens, transports fat-soluble vitamins, produces lymphocytes for immunity."},
{id:"ha17",exam:"HESI",section:"A&P",q:"The largest organ of the body is the:",o:["A. Liver","B. Lung","C. Brain","D. Skin"],a:"D",e:"The skin (integumentary system) is the largest organ by surface area and weight (~16% of body weight). Functions: thermoregulation, protection, sensation, vitamin D synthesis."},
{id:"ha18",exam:"HESI",section:"A&P",q:"Peristalsis is best described as:",o:["A. Voluntary control of sphincter muscles","B. Wave-like smooth muscle contractions moving food through the GI tract","C. Secretion of digestive enzymes into the stomach","D. Absorption of nutrients in the large intestine"],a:"B",e:"Peristalsis = rhythmic involuntary smooth muscle contractions in GI tract wall. Propels food from esophagus → stomach → small intestine → large intestine → rectum."},
{id:"ha19",exam:"HESI",section:"A&P",q:"Which lobe of the brain is primarily responsible for voluntary movement?",o:["A. Occipital lobe","B. Temporal lobe","C. Parietal lobe","D. Frontal lobe"],a:"D",e:"Frontal lobe: voluntary movement (motor cortex), executive function, personality, decision-making. Parietal = sensory processing. Temporal = hearing, memory. Occipital = vision."},
{id:"ha20",exam:"HESI",section:"A&P",q:"What is the role of antidiuretic hormone (ADH)?",o:["A. Increases urine output","B. Decreases blood pressure","C. Promotes water reabsorption in the kidneys","D. Stimulates sodium excretion"],a:"C",e:"ADH (vasopressin) = released by posterior pituitary → kidneys reabsorb water → concentrated urine, decreased urine output. SIADH = excess ADH → water retention → hyponatremia."},
{id:"ha21",exam:"HESI",section:"A&P",q:"Which blood type is the universal DONOR?",o:["A. Type A positive","B. Type AB positive","C. Type O negative","D. Type B negative"],a:"C",e:"O negative = no ABO or Rh antigens → can donate to anyone in emergencies. AB positive = universal RECIPIENT (accepts all types). Know this for emergency transfusion scenarios."},
{id:"ha22",exam:"HESI",section:"A&P",q:"The normal adult respiratory rate is:",o:["A. 8–12 breaths/min","B. 12–20 breaths/min","C. 20–28 breaths/min","D. 28–36 breaths/min"],a:"B",e:"Normal adult RR = 12–20 breaths/min. Tachypnea >20/min. Bradypnea <12/min. <8/min = respiratory emergency. Infants breathe faster (30–60/min)."},
{id:"ha23",exam:"HESI",section:"A&P",q:"The function of the thyroid gland is to produce hormones that regulate:",o:["A. Blood glucose","B. Calcium balance","C. Metabolism and energy levels","D. Blood pressure"],a:"C",e:"Thyroid produces T3 and T4 (require iodine) → regulate metabolic rate, energy, growth, and development. TSH from pituitary stimulates thyroid. Hypothyroid = slowed metabolism."},
{id:"ha24",exam:"HESI",section:"A&P",q:"Which cranial nerve is responsible for controlling heart rate?",o:["A. Trigeminal (V)","B. Facial (VII)","C. Vagus (X)","D. Hypoglossal (XII)"],a:"C",e:"Vagus nerve (CN X) = parasympathetic control of heart (slows HR), lungs, and most abdominal organs. 'VAGA-s' — vegas/wandering nerve because it has widespread effects."},
{id:"ha25",exam:"HESI",section:"A&P",q:"The function of platelets (thrombocytes) is to:",o:["A. Carry oxygen","B. Fight infection","C. Initiate blood clotting","D. Produce antibodies"],a:"C",e:"Platelets = smallest blood cells, essential for hemostasis. When a vessel is damaged, platelets aggregate and form a plug. Normal platelet count = 150,000–400,000/µL. <50,000 = bleeding risk."},
{id:"ha26",exam:"HESI",section:"A&P",q:"Aldosterone acts on the kidneys to:",o:["A. Increase sodium and water excretion","B. Retain sodium and excrete potassium","C. Retain potassium and excrete sodium","D. Inhibit water reabsorption"],a:"B",e:"Aldosterone (adrenal cortex) → kidneys retain Na⁺ (and thus water) + excrete K⁺ → increases blood volume and pressure. Part of the renin-angiotensin-aldosterone system (RAAS)."},
{id:"ha27",exam:"HESI",section:"A&P",q:"The biceps brachii performs which action?",o:["A. Extension of the elbow","B. Flexion of the elbow","C. Rotation of the shoulder","D. Extension of the wrist"],a:"B",e:"Biceps brachii = flexes elbow and supinates forearm. Triceps brachii = extends elbow (antagonist). Opposing muscle pairs (agonist/antagonist) allow controlled movement."},
{id:"ha28",exam:"HESI",section:"A&P",q:"The primary organ of the immune system that produces T lymphocytes is the:",o:["A. Lymph nodes","B. Spleen","C. Bone marrow","D. Thymus"],a:"D",e:"T lymphocytes mature in the THYMUS ('T' for thymus). B lymphocytes mature in BONE MARROW. Lymph nodes = filter lymph. Spleen = filters blood and activates immune response."},
{id:"ha29",exam:"HESI",section:"A&P",q:"Which vitamin requires sunlight for synthesis in the skin?",o:["A. Vitamin A","B. Vitamin B12","C. Vitamin C","D. Vitamin D"],a:"D",e:"Vitamin D (calcitriol) is synthesized in skin from UV-B sunlight exposure. Functions: calcium absorption, bone health, immune function. Deficiency → rickets (children), osteomalacia (adults)."},
{id:"ha30",exam:"HESI",section:"A&P",q:"The cerebellum is primarily responsible for:",o:["A. Language and speech","B. Visual processing","C. Coordination, balance, and fine motor control","D. Regulating emotions"],a:"C",e:"Cerebellum = balance, coordination, and fine motor movements. Damage causes ataxia (uncoordinated movement). Cerebrum = thinking/memory. Brainstem = vital functions."},

// ═══════════════════════════════════════════════
// CRITICAL THINKING — 25 questions
// ═══════════════════════════════════════════════
{id:"hct1",exam:"HESI",section:"Critical Thinking",q:"A patient's O2 saturation drops to 87% on room air. What is the nurse's PRIORITY action?",o:["A. Document the finding and continue monitoring","B. Apply supplemental oxygen immediately","C. Notify dietary of the change","D. Reposition to left lateral Sims position"],a:"B",e:"O2 sat <90% requires IMMEDIATE oxygen intervention. Normal ≥95%. Apply O2 first, then reassess and notify provider. Airway and breathing always first (ABCs)."},
{id:"hct2",exam:"HESI",section:"Critical Thinking",q:"Using Maslow's hierarchy, which need takes HIGHEST priority?",o:["A. Patient requests chaplain visit","B. Patient is crying and needs emotional support","C. Patient is experiencing chest pain and diaphoresis","D. Patient asks for the TV remote"],a:"C",e:"Physiological needs (airway, breathing, circulation) are always first per Maslow's hierarchy. Chest pain with diaphoresis = potential MI = immediate life-threatening emergency."},
{id:"hct3",exam:"HESI",section:"Critical Thinking",q:"A patient verbally reports pain as 2/10 but is grimacing and guarding the abdomen. The best action is to:",o:["A. Accept the verbal report and document 2/10","B. Give pain medication based on the low verbal score","C. Perform a more thorough objective pain and abdominal assessment","D. Ask the family what they think the patient's pain level is"],a:"C",e:"Critical thinking requires evaluating ALL data. Non-verbal cues (grimacing, guarding) contradicting verbal reports require thorough objective reassessment. Both forms of data matter."},
{id:"hct4",exam:"HESI",section:"Critical Thinking",q:"Before giving a medication, you notice the patient's name on the armband doesn't match the MAR. You should:",o:["A. Give the medication — it's likely a clerical error","B. Hold medication, investigate the discrepancy before administering","C. Ask the patient their name and give it if they confirm","D. Give it and document the discrepancy as a near miss afterward"],a:"B",e:"Patient identification is a critical safety check. NEVER give medication when there's an identity discrepancy. Hold, investigate, notify charge nurse. 'The 8 Rights' of medication administration."},
{id:"hct5",exam:"HESI",section:"Critical Thinking",q:"A patient's potassium level is 6.9 mEq/L. The nurse's FIRST action should be:",o:["A. Encourage potassium-rich foods","B. Administer an oral potassium supplement","C. Notify the provider immediately — critical value","D. Recheck in 4 hours before taking action"],a:"C",e:"K+ >6.5 mEq/L = critical hyperkalemia → risk of fatal cardiac arrhythmia. Notify provider immediately. Normal K+ = 3.5–5.0 mEq/L. Any value outside critical range requires immediate action."},
{id:"hct6",exam:"HESI",section:"Critical Thinking",q:"Which finding requires MOST immediate attention?",o:["A. Blood pressure 128/84 mmHg","B. O2 saturation 88% on room air","C. Heart rate 92 bpm","D. Temperature 99.2°F"],a:"B",e:"O2 sat 88% is critically low (normal ≥95%). Hypoxemia = immediate threat to oxygenation. The other values are all near-normal. Airway and breathing → circulation (ABCs)."},
{id:"hct7",exam:"HESI",section:"Critical Thinking",q:"A family member insists on staying during an invasive procedure. The patient has not given consent for this. The nurse should:",o:["A. Allow it to preserve family relationships","B. Ask the patient privately if they consent to the family member's presence","C. Automatically deny family access regardless","D. Ask the physician to make the decision"],a:"B",e:"Patient autonomy and privacy are paramount. Ask the patient privately — away from the family member. They may feel coerced if asked in front of family. HIPAA and patient rights apply."},
{id:"hct8",exam:"HESI",section:"Critical Thinking",q:"You discover a medication error after administering the wrong dose. Your FIRST action should be:",o:["A. Wait to see if the patient develops symptoms","B. Ask a colleague to handle the situation","C. Assess the patient and notify the provider","D. Document the error in the chart before doing anything else"],a:"C",e:"After a medication error: (1) Assess patient for adverse effects, (2) Notify provider, (3) Document per policy, (4) File incident report. Never wait and see — early intervention is critical."},
{id:"hct9",exam:"HESI",section:"Critical Thinking",q:"A postoperative patient has urine output of 18 mL/hr for the past 3 hours. The nurse should FIRST:",o:["A. Document and monitor for another hour","B. Encourage oral fluid intake","C. Notify the provider — output is critically low","D. Irrigate the Foley catheter"],a:"C",e:"Normal urine output ≥30 mL/hr. At 18 mL/hr for 3 hours = oliguria — indicates possible hypovolemia, hemorrhage, or renal hypoperfusion. Requires immediate provider notification."},
{id:"hct10",exam:"HESI",section:"Critical Thinking",q:"Which represents the BEST example of evidence-based practice?",o:["A. Following what the most experienced nurse on the unit does","B. Doing what was taught in nursing school without question","C. Using current peer-reviewed research to guide clinical decisions","D. Following hospital tradition as the standard of care"],a:"C",e:"EBP = integrating best available research evidence + clinical expertise + patient values. Supersedes tradition and seniority. The evidence base changes — stay current."},
{id:"hct11",exam:"HESI",section:"Critical Thinking",q:"A patient competently refuses a blood transfusion for religious reasons. The nurse should:",o:["A. Administer the transfusion anyway — it is life-saving","B. Ask family members to override the decision","C. Document the refusal and notify the provider","D. Call hospital security to manage the situation"],a:"C",e:"Competent adults have the absolute right to refuse treatment, even life-saving treatment. Document thoroughly, notify provider, ensure informed refusal. Respect patient autonomy — it is law."},
{id:"hct12",exam:"HESI",section:"Critical Thinking",q:"When prioritizing care for multiple patients, which patient should be seen FIRST?",o:["A. Patient requesting pain medication for chronic back pain (4/10)","B. Patient who just returned from surgery 30 minutes ago","C. Patient with new onset confusion and slurred speech","D. Patient asking for a lunch tray change"],a:"C",e:"New onset confusion + slurred speech = possible stroke (CVA) or neurological emergency. Time-sensitive — 'Time is brain.' The post-surgical patient needs assessment but is not in acute distress."},
{id:"hct13",exam:"HESI",section:"Critical Thinking",q:"A nurse receives a verbal order over the phone during a code. She should:",o:["A. Refuse to accept verbal orders under any circumstances","B. Write down and read back the order to verify, then document","C. Accept the order verbally without documentation until later","D. Ask the provider to send the order via fax first"],a:"B",e:"Verbal/telephone orders are acceptable in emergencies. Follow policy: write it down → read it back to confirm → document with 'VO' or 'TO' (verbal/telephone order) + provider's name."},
{id:"hct14",exam:"HESI",section:"Critical Thinking",q:"The nurse applies critical thinking when which action occurs?",o:["A. Following protocol without considering individual patient factors","B. Analyzing assessment data to identify a potential safety concern","C. Repeating the same intervention regardless of patient response","D. Delegating all assessments to the nursing assistant"],a:"B",e:"Critical thinking = analyzing data, recognizing patterns, and drawing clinical conclusions. It involves questioning, evaluating evidence, and adjusting the plan based on individual patient data."},
{id:"hct15",exam:"HESI",section:"Critical Thinking",q:"A patient is ordered heparin 5,000 units subcutaneously. Available: heparin 10,000 units/mL. How many mL should be given?",o:["A. 0.25 mL","B. 0.5 mL","C. 0.75 mL","D. 1 mL"],a:"B",e:"5,000 units ÷ 10,000 units/mL = 0.5 mL. Heparin math is high-stakes — double-check with a colleague per policy. Wrong dose can cause hemorrhage or clotting."},
{id:"hct16",exam:"HESI",section:"Critical Thinking",q:"Which nursing intervention is MOST important for a patient on fall precautions?",o:["A. Place call light within reach and keep bed in lowest position","B. Provide thick socks without grips","C. Leave side rails down for patient convenience","D. Encourage patient to get up independently for exercise"],a:"A",e:"Fall prevention: call light in reach, bed lowest position, non-skid footwear, side rails up, clear pathways, no reaching. Falls are a leading cause of preventable hospital injuries."},
{id:"hct17",exam:"HESI",section:"Critical Thinking",q:"A patient asks about a medication, and the nurse is unsure of the information. The best response is to:",o:["A. Provide the best guess based on experience","B. Tell the patient to ask the doctor","C. Look up the medication and provide accurate information","D. Ignore the question and change the subject"],a:"C",e:"Patient education requires accurate information. Never guess about medications — look it up in a drug reference (Micromedex, Lexi-Comp, package insert). Patient safety depends on accurate teaching."},
{id:"hct18",exam:"HESI",section:"Critical Thinking",q:"A newly admitted patient has a sodium level of 122 mEq/L. The priority concern is:",o:["A. Fluid overload","B. Neurological complications from hyponatremia","C. Skin breakdown","D. Nutritional deficit"],a:"B",e:"Severe hyponatremia (Na <130) → osmotic shifts → cerebral edema → seizures, coma, death. Normal Na = 135–145 mEq/L. Na 122 is critically low — neurological monitoring is the priority."},
{id:"hct19",exam:"HESI",section:"Critical Thinking",q:"The nurse receives report that a patient's INR is 5.8 on warfarin. The nurse should FIRST:",o:["A. Administer the next dose of warfarin on schedule","B. Hold the dose and notify the provider — supratherapeutic level","C. Check blood pressure and reassess in 1 hour","D. Encourage increased vitamin K intake"],a:"B",e:"Therapeutic INR = 2–3 (2.5–3.5 for mechanical valves). INR 5.8 = dangerously high bleeding risk. Hold warfarin, notify provider immediately. May require vitamin K (antidote) or FFP."},
{id:"hct20",exam:"HESI",section:"Critical Thinking",q:"A nurse delegates tasks to a nursing assistant (NA). Which task is APPROPRIATE for the NA?",o:["A. Performing a comprehensive assessment","B. Administering medications","C. Measuring and recording vital signs on a stable patient","D. Changing a central line dressing"],a:"C",e:"NAs (CNAs) can perform: vital signs on stable patients, ADL assistance, basic specimen collection, I&O. They CANNOT: assess, administer medications, perform sterile procedures, or interpret data."},
{id:"hct21",exam:"HESI",section:"Critical Thinking",q:"A nurse notices a colleague documenting a procedure that was not completed. She should:",o:["A. Ignore it — not her patient or responsibility","B. Confront the colleague publicly at the nurses' station","C. Report the concern using the facility's chain of command and incident reporting","D. Document over the falsified entry without reporting"],a:"C",e:"Falsifying documentation = serious ethical and legal violation. Follow chain of command: speak to the colleague privately first if safe, then notify charge nurse/manager. Incident report required."},
{id:"hct22",exam:"HESI",section:"Critical Thinking",q:"When caring for a patient in respiratory distress, which assessment finding requires IMMEDIATE escalation?",o:["A. RR 22/min","B. O2 sat 94% on 2L nasal cannula","C. Accessory muscle use with RR 32/min and O2 sat 84%","D. Patient reports mild shortness of breath with exertion"],a:"C",e:"RR 32 + accessory muscle use + O2 sat 84% = severe respiratory distress/failure. Escalate immediately — patient may require BiPAP/intubation. O2 sat 84% = critical hypoxemia."},
{id:"hct23",exam:"HESI",section:"Critical Thinking",q:"The BEST way to verify medication understanding in a patient with low health literacy is:",o:["A. Provide written pamphlets with diagrams","B. Teach verbally and ask the patient to repeat back ('teach-back')","C. Speak louder and use medical terminology","D. Have a family member translate all information"],a:"B",e:"Teach-back method = patient explains information in their own words. Most effective for verifying understanding regardless of literacy level. 'Tell me what you'll do with this medication at home.'"},
{id:"hct24",exam:"HESI",section:"Critical Thinking",q:"A patient's Troponin I level comes back at 2.8 ng/mL (normal <0.04). The nurse should FIRST:",o:["A. Recheck in 6 hours per routine","B. Notify the provider immediately — critical cardiac biomarker","C. Document the result and wait for the physician to review","D. Encourage ambulation to improve cardiac circulation"],a:"B",e:"Elevated troponin = myocardial injury/infarction. Troponin I >0.04 ng/mL is abnormal; 2.8 is markedly elevated. Immediate provider notification, 12-lead EKG, continuous cardiac monitoring."},
{id:"hct25",exam:"HESI",section:"Critical Thinking",q:"A nurse notes that a patient's surgical consent was signed while the patient was under sedation. She should:",o:["A. Proceed with the surgery — the consent was signed","B. Notify the surgeon and hold the procedure until valid consent is obtained","C. Have a family member countersign to validate it","D. Document the concern but allow surgery to continue"],a:"B",e:"Informed consent requires a competent, unmedicated patient. Consent signed under sedation = invalid. Hold the procedure. Notify surgeon and obtain valid consent when patient is competent. This is a legal requirement."},
];

// ─── TEAS 7 — 200 Questions | 4 Sections (Blueprint-matched) ────
const TEAS_QUESTIONS = [
// ═══════════════════════════════════════════════
// READING — 52 questions
// Sub-areas: Key ideas & details (20), Craft & structure (16), Integration of knowledge & ideas (16)
// ═══════════════════════════════════════════════

// — Key Ideas & Details (20) —
{id:"tr1",exam:"TEAS",section:"Reading",q:"Read: 'Nurses who practice mindful handoffs reduce medical errors significantly.' The MAIN IDEA is:",o:["A. All nurses make medical errors","B. Mindful handoffs by nurses are linked to fewer medical errors","C. Medical errors are inevitable","D. Handoffs should be eliminated"],a:"B",e:"Main idea = the central message. The passage says mindful handoffs → fewer errors. It's not saying errors are inevitable or that all nurses make them."},
{id:"tr2",exam:"TEAS",section:"Reading",q:"Which answer BEST summarizes this passage: 'Dehydration affects cognitive function, physical performance, and mood. Even mild dehydration — as little as 1–2% loss of body weight — can impair concentration.'",o:["A. People should drink more water","B. Dehydration impairs cognitive and physical function even at mild levels","C. Concentration problems are caused by mood changes","D. Body weight determines water needs"],a:"B",e:"Summary = main idea + key support. Passage states dehydration (even mild) impairs cognition, performance, and mood. Don't add information not in the passage."},
{id:"tr3",exam:"TEAS",section:"Reading",q:"A patient record states: 'Patient is a 45-year-old female with HTN and T2DM, presenting with chest pain.' What can be INFERRED?",o:["A. She definitely has a heart attack","B. Her conditions and symptoms put her at elevated cardiovascular risk","C. Her diabetes caused the chest pain","D. HTN and T2DM are unrelated to her current complaint"],a:"B",e:"Inference = logical conclusion from evidence. HTN + T2DM = major cardiovascular risk factors. Chest pain in this context warrants cardiac workup — inference, not absolute fact."},
{id:"tr4",exam:"TEAS",section:"Reading",q:"Which detail from a passage BEST supports the claim: 'Nurses experience high rates of occupational burnout'?",o:["A. Nurses wear scrubs to work","B. Nursing is a caring profession","C. Studies show 43% of hospital nurses report emotional exhaustion","D. There is a nursing shortage in rural areas"],a:"C",e:"Supporting detail must directly address the claim. '43% report emotional exhaustion' directly supports burnout rates. The other options are facts but don't support the burnout claim."},
{id:"tr5",exam:"TEAS",section:"Reading",q:"'Despite the antibiotic, the patient's fever persisted.' What does DESPITE signal?",o:["A. The antibiotic caused the fever","B. Contrast — something happened even though a contrary condition existed","C. The antibiotic and fever are unrelated","D. The fever resolved eventually"],a:"B",e:"'Despite' = contrast/concession word. The fever persisted (result) even though the antibiotic was given (expected to help). Other contrast words: although, however, yet, nevertheless."},
{id:"tr6",exam:"TEAS",section:"Reading",q:"What is the DIFFERENCE between a main idea and a supporting detail?",o:["A. Main idea appears only at the end of a paragraph","B. Main idea is the central point; supporting details develop and prove it","C. Supporting details are always statistics","D. Main idea is always stated in the first sentence"],a:"B",e:"Main idea = what the passage is primarily about. Supporting details = specific facts, examples, or evidence that explain or prove the main idea. Main idea may appear anywhere."},
{id:"tr7",exam:"TEAS",section:"Reading",q:"A passage describes three steps for hand hygiene. The text structure is:",o:["A. Compare and contrast","B. Cause and effect","C. Problem and solution","D. Sequential/chronological order"],a:"D",e:"Steps, procedures, and instructions with numbered or ordered sequence = sequential/chronological text structure. Signal words: first, then, next, finally, step 1, step 2."},
{id:"tr8",exam:"TEAS",section:"Reading",q:"'Febrile' can be defined using context in: 'The child was febrile, with a temperature spiking to 104°F.' The context clue is:",o:["A. 'The child'","B. 'with a temperature spiking to 104°F'","C. 'was'","D. 'febrile'"],a:"B",e:"'Temperature spiking to 104°F' is an explanatory context clue — it describes what febrile means (having a high fever) without defining it directly."},
{id:"tr9",exam:"TEAS",section:"Reading",q:"A nurse reads a chart note: 'Patient denies SOB, CP, or palpitations.' What can be concluded?",o:["A. The patient has no cardiac or respiratory disease","B. The patient reports not experiencing shortness of breath, chest pain, or palpitations","C. The patient is lying about symptoms","D. These symptoms were not assessed"],a:"B",e:"'Denies' in medical documentation = patient reports NOT having that symptom. It doesn't mean they are disease-free — it's the patient's subjective report."},
{id:"tr10",exam:"TEAS",section:"Reading",q:"'As a result, the mortality rate decreased by 30%.' 'As a result' signals:",o:["A. Contrast","B. Definition","C. Cause and effect","D. Compare and contrast"],a:"C",e:"'As a result,' 'therefore,' 'consequently,' 'because,' 'thus' = cause-and-effect signal words. Something caused the mortality rate to decrease."},
{id:"tr11",exam:"TEAS",section:"Reading",q:"Which of the following is a FACT rather than an opinion?",o:["A. Nurses are underpaid for their dedication","B. The hospital has 450 beds","C. Patient care would improve if nurses had more autonomy","D. The best nurses are the most empathetic"],a:"B",e:"Facts are verifiable and objective. '450 beds' = a specific number that can be confirmed. Options A, C, and D contain value judgments ('underpaid,' 'best,' 'would improve')."},
{id:"tr12",exam:"TEAS",section:"Reading",q:"A passage about sepsis explains: causes → patient outcomes → prevention measures. This is an example of which structure?",o:["A. Chronological","B. Problem-solution","C. Compare-contrast","D. Cause and effect"],a:"D",e:"Causes → outcomes = cause-and-effect. The passage shows what causes sepsis and what results from it. Prevention measures would be solution, but the primary structure is cause-effect."},
{id:"tr13",exam:"TEAS",section:"Reading",q:"To make an inference from a text, a reader must:",o:["A. Find information explicitly stated","B. Memorize the entire passage","C. Combine text evidence with prior knowledge to reach a logical conclusion","D. Accept all author claims as facts"],a:"C",e:"Inference = text clues + reader's prior knowledge → logical conclusion not directly stated. Read between the lines. Must be supported by evidence — not a wild guess."},
{id:"tr14",exam:"TEAS",section:"Reading",q:"Read: 'Medication errors occur most frequently during medication administration, transcription, and dispensing.' Which is implied?",o:["A. All pharmacists make errors","B. Nurses alone are responsible for medication errors","C. Multiple stages of the medication process carry error risk","D. Dispensing is the most dangerous stage"],a:"C",e:"The passage mentions THREE stages — implying risk exists at multiple points. The passage doesn't rank stages by risk level or blame one profession. Don't over-infer."},
{id:"tr15",exam:"TEAS",section:"Reading",q:"'The patient was dyspneic; furthermore, she had cyanotic fingertips.' FURTHERMORE signals:",o:["A. Contrast","B. Addition of supporting information","C. Cause and effect","D. A summary"],a:"B",e:"'Furthermore,' 'moreover,' 'in addition,' 'also' = addition signal words. They add more supporting evidence to the same point — respiratory distress signs are compounding here."},
{id:"tr16",exam:"TEAS",section:"Reading",q:"Which reading strategy helps identify the main idea of a long passage MOST efficiently?",o:["A. Reading every word from start to finish twice","B. Reading only the last paragraph","C. Skimming topic sentences of each paragraph","D. Memorizing all vocabulary words first"],a:"C",e:"Topic sentences (usually first sentence of each paragraph) contain the main idea. Skimming these gives a quick overview. Reading everything twice is thorough but not efficient for timed tests."},
{id:"tr17",exam:"TEAS",section:"Reading",q:"In a table of contents, Chapter 7 is titled 'Medication Dosage Calculations.' Where would you look for information on pediatric weight-based dosing?",o:["A. Chapter 1","B. Chapter 7","C. The bibliography","D. The preface"],a:"B",e:"Tables of contents organize content by topic. Pediatric dosing is a type of dosage calculation → Chapter 7. Also check the index for specific subtopics within chapters."},
{id:"tr18",exam:"TEAS",section:"Reading",q:"'Conversely, patients in rural areas have less access to specialist care.' CONVERSELY signals:",o:["A. Agreement with the previous point","B. An example of the previous point","C. Contrast with the previous point","D. A cause of the previous point"],a:"C",e:"'Conversely' = on the other hand, in contrast. It introduces an opposite or contrasting idea to what was just stated. Watch for it on inference and structure questions."},
{id:"tr19",exam:"TEAS",section:"Reading",q:"An author's PURPOSE in a research article comparing hand sanitizer to soap is most likely to:",o:["A. Entertain readers with hospital stories","B. Persuade readers to stop using soap","C. Inform readers of research findings on hand hygiene effectiveness","D. Describe the history of hand hygiene"],a:"C",e:"Research articles inform (present data, findings, conclusions). Narrative texts entertain. Persuasive texts argue a position. This is a compare/contrast research article — purpose = inform."},
{id:"tr20",exam:"TEAS",section:"Reading",q:"In the sentence: 'The data, while inconclusive, suggest a trend toward improved outcomes,' the word INCONCLUSIVE means:",o:["A. Definitive and clear","B. Not yet leading to a clear conclusion","C. Incorrect and flawed","D. Highly significant"],a:"B",e:"Inconclusive = not producing a clear result or conclusion. The prefix 'in-' (not) + 'conclusive' (leading to a clear end). Data that is inconclusive still may suggest trends but not prove them."},

// — Craft & Structure (16) —
{id:"tr21",exam:"TEAS",section:"Reading",q:"The author writes: 'Nurses are the unsung heroes of healthcare.' This is an example of:",o:["A. A factual claim","B. Statistical evidence","C. A metaphor/figurative language","D. An explicit definition"],a:"C",e:"'Unsung heroes' is a metaphor — comparing nurses to heroes without using 'like' or 'as.' It's figurative language expressing the author's view. It's opinion/rhetoric, not a verifiable fact."},
{id:"tr22",exam:"TEAS",section:"Reading",q:"Which word has the most NEGATIVE connotation?",o:["A. Thin","B. Slender","C. Svelte","D. Gaunt"],a:"D",e:"All words relate to being thin, but connotations differ. 'Gaunt' implies unhealthy thinness — negative. 'Svelte' and 'slender' = positive/neutral. Word choice affects tone and meaning."},
{id:"tr23",exam:"TEAS",section:"Reading",q:"A nursing article uses mostly first-person ('I', 'we'). This suggests the text is:",o:["A. A research study","B. An objective news report","C. A personal narrative or editorial","D. A policy document"],a:"C",e:"First-person = personal voice → narrative or editorial. Research/policy documents use third-person ('patients,' 'the study shows') to maintain objectivity."},
{id:"tr24",exam:"TEAS",section:"Reading",q:"What is the primary PURPOSE of a glossary in a textbook?",o:["A. To list the chapters","B. To provide definitions of key terms","C. To cite research sources","D. To summarize each chapter"],a:"B",e:"Glossary = alphabetized list of key terms with definitions. Different from index (topic locations), bibliography (sources), and table of contents (chapter list)."},
{id:"tr25",exam:"TEAS",section:"Reading",q:"The word 'HOWEVER' is used to signal:",o:["A. Cause and effect","B. A sequence of steps","C. Contrast or contradiction","D. An example or illustration"],a:"C",e:"'However' = contrast. It reverses direction or introduces an exception. 'The medication was given; however, the pain persisted' — expected result vs. actual result."},
{id:"tr26",exam:"TEAS",section:"Reading",q:"'The results were statistically significant (p<0.05).' What does this mean in the context of research?",o:["A. The results were obviously important","B. There is less than a 5% probability the results occurred by chance","C. 95% of participants improved","D. The study had 95 participants"],a:"B",e:"P<0.05 = statistical significance threshold. There is <5% probability the result is due to chance → the finding is likely real. Understanding research terminology is key for EBP."},
{id:"tr27",exam:"TEAS",section:"Reading",q:"Which sentence uses DENOTATION (literal meaning) rather than connotation?",o:["A. The hospital room felt like a prison","B. The patient was a warrior fighting illness","C. Body temperature was recorded at 102.3°F","D. She was drowning in paperwork"],a:"C",e:"Denotation = literal, exact meaning. '102.3°F' is precise and literal. A, B, and D use figurative language (metaphors/connotations). Clinical documentation should use denotative language."},
{id:"tr28",exam:"TEAS",section:"Reading",q:"An index entry reads: 'blood pressure, 42, 87, 119–125, 200.' This means blood pressure information appears on:",o:["A. Pages 42, 87, and 200 only","B. Pages 42, 87, pages 119 through 125, and page 200","C. 200 different pages","D. A 125-page chapter"],a:"B",e:"Index format: single numbers = individual pages; hyphenated numbers = page ranges. Blood pressure appears on pages 42, 87, the range 119–125, and page 200."},
{id:"tr29",exam:"TEAS",section:"Reading",q:"An author uses bold font for key terms throughout a textbook chapter. This is an example of:",o:["A. Figurative language","B. A visual/typographic text feature","C. An inference","D. Point of view"],a:"B",e:"Text features = formatting tools that help readers navigate/identify key content: bold, italics, headings, tables, diagrams, sidebars. They signal importance and organize information."},
{id:"tr30",exam:"TEAS",section:"Reading",q:"The term 'BIAS' in reading means:",o:["A. An error in grammar","B. A strong unbalanced preference for one perspective","C. A factual claim supported by evidence","D. A summary of the main points"],a:"B",e:"Bias = one-sided perspective, prejudice, or slant in presentation. Biased texts present only one side, use loaded language, or omit contradictory evidence. Critical readers identify bias."},
{id:"tr31",exam:"TEAS",section:"Reading",q:"'For example' signals that the author is about to:",o:["A. Contrast an idea","B. Summarize the passage","C. Provide an illustration or specific instance","D. State the main idea"],a:"C",e:"'For example,' 'for instance,' 'such as,' 'to illustrate' = example signal words. They introduce a specific case that supports or clarifies the general statement."},
{id:"tr32",exam:"TEAS",section:"Reading",q:"What does 'point of view' mean in reading comprehension?",o:["A. The topic of the passage","B. The author's attitude or perspective toward the subject","C. The sequence of events in the passage","D. The vocabulary level of the text"],a:"B",e:"Point of view (POV) = the author's perspective, attitude, and opinions about the topic. Recognizing POV helps identify bias, purpose, and how objectively the topic is presented."},
{id:"tr33",exam:"TEAS",section:"Reading",q:"A passage states: 'Research strongly supports X; however, some studies suggest Y.' The author's primary purpose is to:",o:["A. Argue that X is definitively correct","B. Present a balanced view of conflicting evidence","C. Convince the reader to reject Y","D. Define both X and Y"],a:"B",e:"'However' signals contrast. The author presents support for X AND acknowledges Y — suggesting a balanced, objective presentation of evidence rather than advocacy for one position."},
{id:"tr34",exam:"TEAS",section:"Reading",q:"Which describes the TONE of clinical nursing documentation?",o:["A. Emotional and subjective","B. Figurative and poetic","C. Objective, precise, and factual","D. Informal and conversational"],a:"C",e:"Clinical documentation must be objective (observable facts only), precise (exact measurements), factual (no guessing), and professional. Personal opinions and emotional language are inappropriate."},
{id:"tr35",exam:"TEAS",section:"Reading",q:"'The medication was contraindicated, yet the physician ordered it anyway.' This sentence structure creates:",o:["A. Agreement between two ideas","B. Tension/contrast between expected and actual events","C. A cause-and-effect relationship","D. A definition of contraindicated"],a:"B",e:"'Yet' = contrast word. Contraindicated means 'should not be used' — yet it was ordered. This creates tension/contrast between standard of care and actual action."},
{id:"tr36",exam:"TEAS",section:"Reading",q:"The author uses the statistic: '1 in 3 hospitalized patients will develop a hospital-acquired infection without proper precautions.' What is the intended EFFECT on the reader?",o:["A. To entertain readers with surprising facts","B. To create urgency and emphasize the severity of the problem","C. To prove that precautions never work","D. To define hospital-acquired infections"],a:"B",e:"Specific statistics create urgency and make abstract risks concrete. '1 in 3' emphasizes that HAIs are common — creating a sense of responsibility in healthcare providers."},

// — Integration of Knowledge & Ideas (16) —
{id:"tr37",exam:"TEAS",section:"Reading",q:"A graph shows patient falls decreasing from 45/month to 12/month after implementing hourly rounding. This BEST demonstrates:",o:["A. Hourly rounding definitively causes fall reduction","B. A correlation between hourly rounding and decreased falls","C. Falls will continue to decrease indefinitely","D. 12 falls per month is an acceptable rate"],a:"B",e:"A graph shows correlation (relationship between variables) — not definitive causation. To prove causation, a controlled study is needed. But the correlation is meaningful and supports the practice."},
{id:"tr38",exam:"TEAS",section:"Reading",q:"Which source is MOST reliable for evidence-based nursing practice?",o:["A. A nursing blog post","B. A peer-reviewed journal article from a randomized controlled trial","C. A hospital staff newsletter","D. A social media post by a nurse influencer"],a:"B",e:"Peer-reviewed RCTs = highest level of evidence. Peer review = evaluated by experts before publication. RCTs minimize bias through randomization and controls. Blogs and social media are not peer-reviewed."},
{id:"tr39",exam:"TEAS",section:"Reading",q:"A bar chart compares readmission rates for three hospitals. Hospital A: 18%, B: 12%, C: 22%. What can be concluded?",o:["A. Hospital B has the lowest readmission rate and is likely performing best on this measure","B. Hospital C has the best patient care","C. All hospitals perform equally","D. These rates prove Hospital A causes readmissions"],a:"A",e:"Lower readmission rate generally indicates better care coordination/outcomes. Hospital B (12%) has the lowest rate. Data interpretation: don't over-interpret — this is one metric among many."},
{id:"tr40",exam:"TEAS",section:"Reading",q:"Which distinction is MOST important when evaluating an information source?",o:["A. Length of the article","B. Publisher's name recognition","C. Whether the source is peer-reviewed and current","D. Whether the author is famous"],a:"C",e:"Credible sources: peer-reviewed (expert-vetted), current (recently published), credible author credentials, reputable publisher. Age matters in healthcare — guidelines change. Peer review reduces bias."},
{id:"tr41",exam:"TEAS",section:"Reading",q:"A table shows medication side effects by frequency: Common >10%, Occasional 1–10%, Rare <1%. A medication shows 'nausea: occasional.' What does this mean?",o:["A. 1–10% of patients experience nausea","B. Nausea happens very rarely","C. More than 10% of patients experience nausea","D. The medication causes nausea in all patients"],a:"A",e:"Reading tables requires using the defined key/legend. 'Occasional = 1–10%' per the table's definition. This is a data interpretation skill critical for understanding drug references."},
{id:"tr42",exam:"TEAS",section:"Reading",q:"Two passages both discuss pain management: Passage 1 focuses on opioids; Passage 2 focuses on non-pharmacological approaches. Which conclusion can be drawn from reading BOTH?",o:["A. Non-pharmacological approaches are always superior","B. Opioids should be eliminated from pain management","C. Pain management involves multiple approaches that can complement each other","D. Both passages are wrong"],a:"C",e:"Synthesizing multiple sources = combining information to draw broader conclusions. Neither passage claims to be the only approach — together they suggest a comprehensive, multimodal strategy."},
{id:"tr43",exam:"TEAS",section:"Reading",q:"Which is an example of a LOGICAL FALLACY in an argument?",o:["A. Using research statistics to support a claim","B. Providing multiple expert opinions","C. 'Nurse A gave a bad injection; therefore, all nurses are incompetent'","D. Presenting both sides of a clinical debate"],a:"C",e:"This is 'hasty generalization' — drawing a broad conclusion from one example. Logical fallacies undermine arguments. Other fallacies: ad hominem (personal attacks), straw man (misrepresenting argument), false dichotomy."},
{id:"tr44",exam:"TEAS",section:"Reading",q:"An author cites a 30-year-old study to support a current claim about antibiotic effectiveness. What concern does this raise?",o:["A. None — older studies are more reliable","B. Antibiotic resistance patterns and guidelines have changed significantly since then","C. The study must be wrong if it's that old","D. All studies older than 10 years are irrelevant"],a:"B",e:"Currency matters in healthcare. Antibiotic resistance is rapidly evolving — a 30-year-old study may not reflect current resistance patterns, current guidelines, or current drug formulations."},
{id:"tr45",exam:"TEAS",section:"Reading",q:"Which is the STRONGEST evidence to support a new nursing intervention?",o:["A. One nurse's positive personal experience","B. A single case study","C. A systematic review of multiple randomized controlled trials","D. An expert panel's opinion"],a:"C",e:"Evidence hierarchy (strongest to weakest): Systematic review/meta-analysis > RCT > Cohort study > Case study > Expert opinion > Personal experience. Systematic reviews aggregate multiple RCTs."},
{id:"tr46",exam:"TEAS",section:"Reading",q:"A passage states: 'Regular exercise reduces the risk of cardiovascular disease.' Which graphic would BEST illustrate this?",o:["A. A pie chart showing types of exercise","B. A line graph showing cardiovascular disease rates in exercisers vs. non-exercisers over time","C. A table of exercise equipment costs","D. A diagram of the heart's anatomy"],a:"B",e:"A line graph comparing two groups over time best illustrates a relationship/trend between exercise and cardiovascular disease risk. Pie charts show proportions; tables show comparisons of multiple items."},
{id:"tr47",exam:"TEAS",section:"Reading",q:"'The study was double-blind.' This means:",o:["A. Both researchers and participants were blind","B. Only the participants didn't know which group they were in","C. Neither participants nor researchers knew who received the treatment","D. The study had two blind participants"],a:"C",e:"Double-blind = neither participants nor researchers know who is in the treatment vs. control group. Reduces both participant bias and researcher bias. Gold standard for clinical drug trials."},
{id:"tr48",exam:"TEAS",section:"Reading",q:"Which situation requires checking MULTIPLE sources before accepting information?",o:["A. Looking up a well-established anatomical fact in a textbook","B. Finding a new claim about a supplement reducing cancer risk on a single website","C. Confirming a patient's date of birth in the chart","D. Reading a hospital's mission statement"],a:"B",e:"Extraordinary claims, single-source health claims, and non-peer-reviewed information require verification. A single supplement website is not reliable. Cross-reference with peer-reviewed research."},
{id:"tr49",exam:"TEAS",section:"Reading",q:"A graph's y-axis starts at 50% instead of 0%. This can:",o:["A. Make the data more accurate","B. Exaggerate differences between values visually","C. Reduce the number of data points","D. Improve readability without distorting data"],a:"B",e:"Truncated y-axes (not starting at zero) can make small differences appear much larger — a visual bias technique. Critical readers evaluate graph axes and scales before drawing conclusions."},
{id:"tr50",exam:"TEAS",section:"Reading",q:"Which best describes PLAGIARISM in academic writing?",o:["A. Using too many statistics in a paper","B. Presenting another's ideas or words as your own without attribution","C. Writing in first person","D. Using difficult vocabulary"],a:"B",e:"Plagiarism = using someone else's ideas, words, or data without proper citation/attribution. Academic integrity violation with serious consequences. Always cite sources in research papers."},
{id:"tr51",exam:"TEAS",section:"Reading",q:"When reading a medical research abstract, which section tells you WHAT the study found?",o:["A. Introduction","B. Methods","C. Results","D. Discussion"],a:"C",e:"Abstract structure: Introduction (background), Methods (how), Results (what was found — data), Discussion (what it means). Results section contains the raw findings — numbers, statistics, outcomes."},
{id:"tr52",exam:"TEAS",section:"Reading",q:"'Immunocompromised patients are at greater risk for opportunistic infections.' What inference can be drawn?",o:["A. All infections are the same in all patients","B. A weakened immune system reduces the ability to fight infections that healthy immune systems handle","C. Immunocompromised patients should be isolated from everyone","D. Opportunistic infections are always fatal"],a:"B",e:"Inference: immunocompromised = weakened immune system → opportunistic infections (normally suppressed by healthy immunity) can thrive. This directly follows from the term 'immunocompromised.'"},

// ═══════════════════════════════════════════════
// MATH — 45 questions
// Sub-areas: Numbers & Algebra (25), Measurement & Data (20)
// ═══════════════════════════════════════════════

// — Numbers & Algebra (25) —
{id:"tm1",exam:"TEAS",section:"Math",q:"Solve: 3/8 + 5/12",o:["A. 8/20","B. 19/24","C. 7/12","D. 11/20"],a:"B",e:"LCD of 8 and 12 = 24. 3/8 = 9/24; 5/12 = 10/24. 9/24 + 10/24 = 19/24."},
{id:"tm2",exam:"TEAS",section:"Math",q:"Solve for x: 5x − 3 = 2x + 12",o:["A. x = 3","B. x = 4","C. x = 5","D. x = 6"],a:"C",e:"5x − 2x = 12 + 3 → 3x = 15 → x = 5."},
{id:"tm3",exam:"TEAS",section:"Math",q:"What is 40% of 75?",o:["A. 25","B. 28","C. 30","D. 32"],a:"C",e:"40% × 75 = 0.40 × 75 = 30."},
{id:"tm4",exam:"TEAS",section:"Math",q:"Order from least to greatest: 0.45, 3/8, 47%",o:["A. 0.45, 3/8, 47%","B. 3/8, 0.45, 47%","C. 47%, 0.45, 3/8","D. 3/8, 47%, 0.45"],a:"B",e:"Convert to decimals: 3/8=0.375, 0.45=0.45, 47%=0.47. Order: 0.375 < 0.45 < 0.47."},
{id:"tm5",exam:"TEAS",section:"Math",q:"Simplify: (3² × 4) − (2³ + 6)",o:["A. 20","B. 22","C. 24","D. 26"],a:"B",e:"(9 × 4) − (8 + 6) = 36 − 14 = 22. Apply order of operations: exponents → multiplication → addition/subtraction."},
{id:"tm6",exam:"TEAS",section:"Math",q:"A medication label reads: 400 mg per 10 mL. How many mL for a 600 mg dose?",o:["A. 12 mL","B. 14 mL","C. 15 mL","D. 18 mL"],a:"C",e:"Proportion: 400/10 = 600/x → x = (600 × 10) ÷ 400 = 6000 ÷ 400 = 15 mL."},
{id:"tm7",exam:"TEAS",section:"Math",q:"Convert 2 3/4 to an improper fraction.",o:["A. 9/4","B. 11/4","C. 13/4","D. 5/2"],a:"B",e:"2 3/4 = (2×4 + 3)/4 = 11/4. Check: 11 ÷ 4 = 2.75 = 2 3/4 ✓"},
{id:"tm8",exam:"TEAS",section:"Math",q:"If a car travels 240 miles in 4 hours, what is the average speed?",o:["A. 50 mph","B. 55 mph","C. 60 mph","D. 65 mph"],a:"C",e:"Speed = distance ÷ time = 240 ÷ 4 = 60 mph. Rate × time = distance is a key formula for word problems."},
{id:"tm9",exam:"TEAS",section:"Math",q:"A nurse earns $31.50/hr. She works 36 hours in one week. What is her gross pay?",o:["A. $1,094","B. $1,098","C. $1,112","D. $1,134"],a:"D",e:"$31.50 × 36 = $1,134."},
{id:"tm10",exam:"TEAS",section:"Math",q:"Simplify: 5/6 − 1/4",o:["A. 4/2","B. 7/12","C. 4/12","D. 1/2"],a:"B",e:"LCD = 12. 5/6 = 10/12; 1/4 = 3/12. 10/12 − 3/12 = 7/12."},
{id:"tm11",exam:"TEAS",section:"Math",q:"What is 0.008 written as a percentage?",o:["A. 0.8%","B. 8%","C. 0.08%","D. 80%"],a:"A",e:"Multiply by 100 to convert decimal to percent: 0.008 × 100 = 0.8%."},
{id:"tm12",exam:"TEAS",section:"Math",q:"Solve: −4(3 − 7) + 2²",o:["A. 12","B. 16","C. 18","D. 20"],a:"D",e:"−4(3−7) + 2² = −4(−4) + 4 = 16 + 4 = 20. Parentheses first: 3−7=−4. Then: −4×−4=+16. Then: +4."},
{id:"tm13",exam:"TEAS",section:"Math",q:"A medication requires 0.02 mg/kg. A patient weighs 65 kg. What is the correct dose?",o:["A. 1.0 mg","B. 1.3 mg","C. 1.5 mg","D. 1.8 mg"],a:"B",e:"0.02 × 65 = 1.3 mg. Weight-based dosing is essential for accurate pharmacotherapy."},
{id:"tm14",exam:"TEAS",section:"Math",q:"Which of the following is equivalent to 5/8?",o:["A. 0.525","B. 0.575","C. 0.625","D. 0.675"],a:"C",e:"5 ÷ 8 = 0.625. Verify: 0.625 × 8 = 5 ✓. Common nursing fractions to know: 1/4=0.25, 1/3≈0.33, 1/2=0.5, 3/4=0.75."},
{id:"tm15",exam:"TEAS",section:"Math",q:"If 3 is 15% of a number, what is the number?",o:["A. 15","B. 18","C. 20","D. 25"],a:"C",e:"3 = 15% × n → n = 3 ÷ 0.15 = 20. Or: 3/0.15 = 20."},
{id:"tm16",exam:"TEAS",section:"Math",q:"A hospital has 320 beds. If 85% are occupied, how many patients are currently admitted?",o:["A. 255","B. 264","C. 272","D. 280"],a:"C",e:"320 × 0.85 = 272 patients."},
{id:"tm17",exam:"TEAS",section:"Math",q:"Multiply: 2/3 × 9/4",o:["A. 11/12","B. 3/2","C. 2/3","D. 18/7"],a:"B",e:"2/3 × 9/4 = 18/12 = 3/2. Multiply numerators (2×9=18), multiply denominators (3×4=12), then simplify (18/12 = 3/2)."},
{id:"tm18",exam:"TEAS",section:"Math",q:"What is the value of |−15| + |8|?",o:["A. −7","B. 7","C. 23","D. −23"],a:"C",e:"Absolute value = distance from zero, always positive. |−15| = 15; |8| = 8. 15 + 8 = 23."},
{id:"tm19",exam:"TEAS",section:"Math",q:"A recipe uses 3 1/2 cups of flour per batch. For 4 batches, how much flour is needed?",o:["A. 12 cups","B. 13 cups","C. 14 cups","D. 14.5 cups"],a:"C",e:"3.5 × 4 = 14 cups. Convert mixed number: 3 1/2 = 7/2 = 3.5."},
{id:"tm20",exam:"TEAS",section:"Math",q:"What is the ratio of 45 to 15 in simplest form?",o:["A. 3:1","B. 9:3","C. 5:1","D. 4:1"],a:"A",e:"45:15 = 45/15 = 3/1 = 3:1. Divide both numbers by GCF (15). Ratios appear in medication dosing and staffing calculations."},
{id:"tm21",exam:"TEAS",section:"Math",q:"Solve: 7.2 × 0.05",o:["A. 0.36","B. 0.036","C. 3.6","D. 36"],a:"A",e:"7.2 × 0.05 = 0.36. Decimal multiplication: 72 × 5 = 360, then place decimal 3 places from right = 0.360."},
{id:"tm22",exam:"TEAS",section:"Math",q:"A patient's weight changed from 80 kg to 86 kg in one week. What is the percent increase?",o:["A. 6.5%","B. 7%","C. 7.5%","D. 8%"],a:"C",e:"Percent change = (new − old) ÷ old × 100 = (86−80) ÷ 80 × 100 = 6/80 × 100 = 7.5%."},
{id:"tm23",exam:"TEAS",section:"Math",q:"Which of the following is NOT a rational number?",o:["A. 0.333...","B. √2","C. −5","D. 2/7"],a:"B",e:"Rational numbers = can be expressed as a fraction of two integers. √2 = 1.41421356... (non-repeating, non-terminating) = irrational. 0.333... = 1/3 (rational)."},
{id:"tm24",exam:"TEAS",section:"Math",q:"If x = −3 and y = 4, what is 2x² − y?",o:["A. 10","B. 12","C. 14","D. 16"],a:"C",e:"2(−3)² − 4 = 2(9) − 4 = 18 − 4 = 14. Square the negative first: (−3)² = 9 (positive)."},
{id:"tm25",exam:"TEAS",section:"Math",q:"A solution is diluted so that 1 part concentrate is mixed with 4 parts water. What percent of the final solution is concentrate?",o:["A. 20%","B. 25%","C. 40%","D. 4%"],a:"A",e:"Total parts = 1 + 4 = 5. Concentrate = 1/5 = 0.20 = 20%. Dilution ratios are important in lab and medication preparation."},

// — Measurement & Data (20) —
{id:"tm26",exam:"TEAS",section:"Math",q:"Convert 5 feet 9 inches to inches total.",o:["A. 59 inches","B. 65 inches","C. 69 inches","D. 70 inches"],a:"C",e:"5 feet × 12 in/ft = 60 inches. 60 + 9 = 69 inches. Used for calculating BMI and growth chart plotting."},
{id:"tm27",exam:"TEAS",section:"Math",q:"A patient's temperature is 39.4°C. Convert to Fahrenheit. [F = (C × 9/5) + 32]",o:["A. 101.2°F","B. 102.0°F","C. 102.9°F","D. 103.5°F"],a:"C",e:"(39.4 × 9/5) + 32 = (39.4 × 1.8) + 32 = 70.92 + 32 = 102.92 ≈ 102.9°F."},
{id:"tm28",exam:"TEAS",section:"Math",q:"What is the mean (average) of: 78, 85, 91, 67, 84?",o:["A. 79","B. 81","C. 83","D. 85"],a:"B",e:"Sum = 78+85+91+67+84 = 405. Mean = 405 ÷ 5 = 81."},
{id:"tm29",exam:"TEAS",section:"Math",q:"What is the MEDIAN of: 14, 22, 8, 31, 19, 27, 11?",o:["A. 14","B. 19","C. 22","D. 27"],a:"B",e:"Ordered: 8, 11, 14, 19, 22, 27, 31. Middle value (4th of 7) = 19."},
{id:"tm30",exam:"TEAS",section:"Math",q:"Convert 2.5 kg to grams.",o:["A. 250 g","B. 2,500 g","C. 25,000 g","D. 0.25 g"],a:"B",e:"1 kg = 1,000 g. 2.5 × 1,000 = 2,500 g. Metric conversions are fundamental in nursing (drug weights, patient weight)."},
{id:"tm31",exam:"TEAS",section:"Math",q:"A bar graph shows patient satisfaction scores: Unit A = 88%, B = 76%, C = 92%, D = 81%. Which unit scores second highest?",o:["A. Unit A","B. Unit B","C. Unit C","D. Unit D"],a:"A",e:"Order highest to lowest: C(92%), A(88%), D(81%), B(76%). Second highest = Unit A at 88%."},
{id:"tm32",exam:"TEAS",section:"Math",q:"A study finds that patients who received intervention X had outcomes: improved (60%), unchanged (25%), worse (15%). What percentage did NOT improve?",o:["A. 25%","B. 35%","C. 40%","D. 60%"],a:"C",e:"Not improved = unchanged + worse = 25% + 15% = 40%. Reading data tables requires careful category identification."},
{id:"tm33",exam:"TEAS",section:"Math",q:"How many milliliters are in 2.5 liters?",o:["A. 250 mL","B. 2,500 mL","C. 25 mL","D. 25,000 mL"],a:"B",e:"1 L = 1,000 mL. 2.5 × 1,000 = 2,500 mL. Critical for IV fluid calculations."},
{id:"tm34",exam:"TEAS",section:"Math",q:"A rectangle is 8 cm long and 5 cm wide. What is its area?",o:["A. 26 cm²","B. 40 cm²","C. 13 cm²","D. 80 cm²"],a:"B",e:"Area of rectangle = length × width = 8 × 5 = 40 cm². Relevant for wound measurement documentation."},
{id:"tm35",exam:"TEAS",section:"Math",q:"A pie chart shows sleep disorder types: Insomnia 45%, Sleep apnea 30%, Narcolepsy 15%, Other 10%. Which two categories together account for 75%?",o:["A. Insomnia + Other","B. Sleep apnea + Narcolepsy","C. Insomnia + Sleep apnea","D. Narcolepsy + Other"],a:"C",e:"Insomnia (45%) + Sleep apnea (30%) = 75%. Pie chart reading: identify and add specific sectors."},
{id:"tm36",exam:"TEAS",section:"Math",q:"What is the MODE of: 4, 7, 2, 9, 7, 3, 7, 5?",o:["A. 2","B. 5","C. 7","D. 9"],a:"C",e:"Mode = most frequently occurring value. 7 appears 3 times; all others appear once. Mode is useful for identifying the most common result in a data set."},
{id:"tm37",exam:"TEAS",section:"Math",q:"A medication comes in 500 mg tablets. The order is for 1.5 g. How many tablets?",o:["A. 1 tablet","B. 2 tablets","C. 3 tablets","D. 4 tablets"],a:"C",e:"Convert: 1.5 g = 1,500 mg. 1,500 ÷ 500 = 3 tablets."},
{id:"tm38",exam:"TEAS",section:"Math",q:"Convert 72 inches to feet.",o:["A. 5 feet","B. 5.5 feet","C. 6 feet","D. 6.5 feet"],a:"C",e:"72 ÷ 12 = 6 feet. Conversely, 6 × 12 = 72. Used in height documentation and dosing calculations."},
{id:"tm39",exam:"TEAS",section:"Math",q:"A line graph shows blood glucose at 8 AM: 95, 12 PM: 140, 4 PM: 120, 8 PM: 105. When was glucose HIGHEST?",o:["A. 8 AM","B. 12 PM","C. 4 PM","D. 8 PM"],a:"B",e:"Read the highest point on the line graph: 140 at 12 PM. Post-meal (post-prandial) glucose peaks are expected after eating."},
{id:"tm40",exam:"TEAS",section:"Math",q:"What is the RANGE of: 15, 28, 42, 9, 33, 21?",o:["A. 27","B. 31","C. 33","D. 42"],a:"C",e:"Range = maximum − minimum = 42 − 9 = 33. Range measures the spread of a data set."},
{id:"tm41",exam:"TEAS",section:"Math",q:"A patient's BMI is calculated as weight (kg) ÷ height² (m²). Weight = 70 kg; height = 1.75 m. What is the BMI?",o:["A. 21.6","B. 22.9","C. 24.5","D. 26.0"],a:"B",e:"1.75² = 3.0625. 70 ÷ 3.0625 = 22.9. Normal BMI = 18.5–24.9. Overweight = 25–29.9. Obese = ≥30."},
{id:"tm42",exam:"TEAS",section:"Math",q:"Convert 250 mL to fluid ounces. (1 fl oz ≈ 30 mL)",o:["A. 6.5 fl oz","B. 7 fl oz","C. 8 fl oz","D. 8.3 fl oz"],a:"D",e:"250 ÷ 30 = 8.33 ≈ 8.3 fl oz. Used when patients track fluid intake in ounces (e.g., cup of juice = 8 fl oz)."},
{id:"tm43",exam:"TEAS",section:"Math",q:"A scatter plot shows a positive correlation between study hours and exam scores. This means:",o:["A. More study hours guarantee higher scores","B. There is a general trend: more study hours tend to associate with higher scores","C. All students who studied more scored perfectly","D. Study hours cause exam success"],a:"B",e:"Positive correlation = as one variable increases, the other tends to increase. NOT causation — many variables affect exam scores. Scatter plots visualize correlation strength and direction."},
{id:"tm44",exam:"TEAS",section:"Math",q:"How many liters is 4,500 mL?",o:["A. 0.45 L","B. 4.5 L","C. 45 L","D. 450 L"],a:"B",e:"4,500 ÷ 1,000 = 4.5 L. A typical adult needs 2–3 L of fluid daily. IV fluid bags come in 1 L (1,000 mL) bags."},
{id:"tm45",exam:"TEAS",section:"Math",q:"What is the probability of randomly selecting a red card from a standard 52-card deck?",o:["A. 1/4","B. 1/2","C. 1/3","D. 1/13"],a:"B",e:"26 red cards (hearts + diamonds) out of 52 total. Probability = 26/52 = 1/2. Basic probability: favorable outcomes ÷ total outcomes."},

// ═══════════════════════════════════════════════
// SCIENCE — 65 questions
// Sub-areas: A&P (26), Biology (13), Chemistry (12), Scientific Reasoning (14)
// ═══════════════════════════════════════════════

// — Human Anatomy & Physiology (26) —
{id:"ts1",exam:"TEAS",section:"Science",q:"Which blood type is the universal recipient?",o:["A. Type O negative","B. Type A positive","C. Type B negative","D. Type AB positive"],a:"D",e:"AB positive = universal recipient (has A, B, and Rh antigens → no antibodies against any type). O negative = universal donor (no antigens → safe for all). Memorize both."},
{id:"ts2",exam:"TEAS",section:"Science",q:"The lymphatic system returns excess fluid to the bloodstream via which structures?",o:["A. Arteries","B. Lymphatic capillaries and ducts","C. Venules","D. Capillary beds directly"],a:"B",e:"Lymphatic capillaries absorb excess interstitial fluid → lymph vessels → lymph ducts (thoracic duct, right lymphatic duct) → subclavian veins → bloodstream."},
{id:"ts3",exam:"TEAS",section:"Science",q:"The epiglottis prevents food from entering the:",o:["A. Esophagus","B. Pharynx","C. Larynx and trachea","D. Stomach"],a:"C",e:"Epiglottis = flap of cartilage that closes over the larynx during swallowing, directing food to the esophagus. Aspiration (food in trachea) = life-threatening risk."},
{id:"ts4",exam:"TEAS",section:"Science",q:"What is the primary function of the large intestine?",o:["A. Chemical digestion of fats","B. Absorption of water and formation of feces","C. Absorption of vitamins and minerals","D. Mechanical digestion of food"],a:"B",e:"Large intestine (colon): reabsorbs water from undigested material → forms, stores, and eliminates feces. Small intestine = primary site of nutrient absorption."},
{id:"ts5",exam:"TEAS",section:"Science",q:"Which hormone is produced by the posterior pituitary to regulate water balance?",o:["A. Cortisol","B. Aldosterone","C. ADH (antidiuretic hormone)","D. Oxytocin only"],a:"C",e:"ADH (vasopressin) is released by posterior pituitary → kidneys reabsorb water → concentrated urine. Dehydration/osmolarity triggers ADH release. SIADH = excess ADH."},
{id:"ts6",exam:"TEAS",section:"Science",q:"The cerebrum is divided into how many lobes?",o:["A. 2","B. 3","C. 4","D. 5"],a:"C",e:"4 lobes per hemisphere: Frontal (executive function/movement), Parietal (sensory), Temporal (hearing/memory), Occipital (vision). 4 lobes × 2 hemispheres = 8 lobes total."},
{id:"ts7",exam:"TEAS",section:"Science",q:"Which structure connects muscle to bone?",o:["A. Ligament","B. Tendon","C. Cartilage","D. Fascia"],a:"B",e:"Tendon = connects MUSCLE to BONE (dense connective tissue). Ligament = connects BONE to BONE. Memory: Tendon = T for tied to bone. Cartilage = cushioning at joint surfaces."},
{id:"ts8",exam:"TEAS",section:"Science",q:"The right ventricle of the heart pumps blood to the:",o:["A. Aorta and systemic circulation","B. Left atrium","C. Pulmonary artery and lungs","D. Superior vena cava"],a:"C",e:"Right ventricle → pulmonary artery → lungs (for oxygenation). Left ventricle → aorta → systemic circulation. Trace blood flow: body → right heart → lungs → left heart → body."},
{id:"ts9",exam:"TEAS",section:"Science",q:"The renal pelvis is the:",o:["A. Filtering unit of the kidney","B. Outer layer of the kidney","C. Funnel-shaped structure that collects urine from calyces","D. The tube that carries urine to the bladder"],a:"C",e:"Renal pelvis = central collecting area of kidney. Calyces collect urine from nephrons → renal pelvis → ureter → bladder. The ureter carries urine from kidney to bladder."},
{id:"ts10",exam:"TEAS",section:"Science",q:"What is the role of surfactant in the lungs?",o:["A. Transport oxygen to blood cells","B. Reduce surface tension in alveoli to prevent collapse","C. Filter particles from inhaled air","D. Regulate breathing rate"],a:"B",e:"Surfactant (produced by type II pneumocytes) reduces surface tension in alveoli, preventing collapse (atelectasis) during exhalation. Premature infants lack surfactant → respiratory distress syndrome."},
{id:"ts11",exam:"TEAS",section:"Science",q:"Which type of joint allows the most range of motion?",o:["A. Hinge joint","B. Pivot joint","C. Ball-and-socket joint","D. Gliding joint"],a:"C",e:"Ball-and-socket joint (hip, shoulder) = greatest ROM (flexion, extension, abduction, adduction, rotation, circumduction). Hinge = one plane only (elbow, knee). Pivot = rotation only (atlas-axis)."},
{id:"ts12",exam:"TEAS",section:"Science",q:"The function of the gallbladder is to:",o:["A. Produce bile","B. Store and concentrate bile","C. Produce digestive enzymes","D. Filter bile for the liver"],a:"B",e:"Gallbladder stores and concentrates bile produced by the LIVER. When fat enters the duodenum, cholecystokinin (CCK) triggers gallbladder contraction → bile released to emulsify fats."},
{id:"ts13",exam:"TEAS",section:"Science",q:"Which cells produce antibodies?",o:["A. T lymphocytes","B. Natural killer cells","C. Neutrophils","D. B lymphocytes (plasma cells)"],a:"D",e:"B lymphocytes mature into plasma cells → produce antibodies (immunoglobulins). T lymphocytes = cell-mediated immunity (destroy infected cells). NK cells = non-specific first responders."},
{id:"ts14",exam:"TEAS",section:"Science",q:"Normal adult cardiac output is approximately:",o:["A. 1–2 L/min","B. 5–6 L/min","C. 10–12 L/min","D. 15–20 L/min"],a:"B",e:"CO = HR × SV (stroke volume). At rest: ~70 bpm × ~70 mL = ~5 L/min. CO increases with exercise. Decreased CO (heart failure) → inadequate tissue perfusion."},
{id:"ts15",exam:"TEAS",section:"Science",q:"The hormone calcitonin is released by the thyroid to:",o:["A. Increase blood calcium","B. Decrease blood calcium by promoting bone deposition","C. Regulate metabolism","D. Control heart rate"],a:"B",e:"Calcitonin (thyroid C-cells) lowers blood calcium by inhibiting osteoclasts and promoting calcium deposition in bone. Parathyroid hormone (PTH) does the opposite — raises calcium."},
{id:"ts16",exam:"TEAS",section:"Science",q:"Which structure of the ear converts sound vibrations to nerve impulses?",o:["A. Tympanic membrane","B. Ossicles (malleus, incus, stapes)","C. Cochlea","D. Semicircular canals"],a:"C",e:"Cochlea = spiral organ in inner ear. Hair cells in cochlea convert mechanical vibrations to electrical signals → auditory nerve → brain. Semicircular canals = balance (not hearing)."},
{id:"ts17",exam:"TEAS",section:"Science",q:"The primary site of nutrient absorption in the digestive system is the:",o:["A. Stomach","B. Large intestine","C. Small intestine","D. Esophagus"],a:"C",e:"Small intestine (duodenum, jejunum, ileum) = primary absorption site. Villi and microvilli (brush border) dramatically increase surface area for absorbing carbs, proteins, fats, vitamins, minerals."},
{id:"ts18",exam:"TEAS",section:"Science",q:"What is the function of the corpus luteum?",o:["A. Produces FSH after ovulation","B. Produces progesterone to maintain the uterine lining","C. Releases the egg during ovulation","D. Produces estrogen before ovulation only"],a:"B",e:"After ovulation, the ruptured follicle becomes the corpus luteum → produces progesterone (and some estrogen) to maintain uterine lining for potential implantation. If no pregnancy, it degenerates."},
{id:"ts19",exam:"TEAS",section:"Science",q:"The ANS (autonomic nervous system) consists of the sympathetic and parasympathetic divisions. The sympathetic division does which of the following?",o:["A. Decreases heart rate","B. Promotes digestion","C. Prepares the body for fight-or-flight (increases HR, dilates pupils)","D. Constricts bronchioles"],a:"C",e:"Sympathetic = fight-or-flight: ↑HR, ↑BP, dilated pupils, dilated bronchioles, inhibits digestion. Parasympathetic (SLUDD) = rest-and-digest: ↓HR, promotes digestion, constricts pupils."},
{id:"ts20",exam:"TEAS",section:"Science",q:"Osteoblasts are cells responsible for:",o:["A. Destroying bone tissue","B. Building and forming new bone","C. Producing cartilage","D. Transmitting pain signals from bone"],a:"B",e:"Osteoblasts = bone BUILDERS (synthesize bone matrix). Osteoclasts = bone destroyers (resorb bone). Osteocytes = mature bone cells in lacunae. Balance of osteoblast/osteoclast activity maintains bone density."},
{id:"ts21",exam:"TEAS",section:"Science",q:"What is the primary function of the spleen?",o:["A. Produce T lymphocytes","B. Filter blood and remove old red blood cells","C. Produce bile","D. Store platelets only"],a:"B",e:"Spleen = filters blood, removes old/damaged RBCs, stores platelets, and activates immune response. Also stores blood that can be released during hemorrhage. NOT a vital organ (can be removed)."},
{id:"ts22",exam:"TEAS",section:"Science",q:"The process of hemostasis involves which CORRECT sequence?",o:["A. Platelet plug → vascular spasm → coagulation","B. Coagulation → vascular spasm → platelet plug","C. Vascular spasm → platelet plug formation → coagulation cascade","D. Fibrin clot → vascular spasm → platelet aggregation"],a:"C",e:"Hemostasis order: (1) Vascular spasm (immediate vasoconstriction), (2) Platelet plug formation, (3) Coagulation cascade (fibrin clot). This sequence stops bleeding progressively."},
{id:"ts23",exam:"TEAS",section:"Science",q:"Which is NOT a function of the liver?",o:["A. Detoxification of drugs and alcohol","B. Production of clotting factors","C. Storage of glucose as glycogen","D. Filtration of lymph"],a:"D",e:"Lymph is filtered by lymph nodes — NOT the liver. Liver functions: detox, bile production, clotting factor synthesis, glycogen storage, albumin production, cholesterol regulation."},
{id:"ts24",exam:"TEAS",section:"Science",q:"The stretch reflex is an example of which type of nerve pathway?",o:["A. A voluntary pathway through the cerebral cortex","B. A reflex arc through the spinal cord","C. A cranial nerve response","D. An autonomic response through the medulla"],a:"B",e:"Reflex arc = sensory neuron → interneuron (spinal cord) → motor neuron → muscle. No brain involvement = faster response. Example: patellar (knee-jerk) reflex."},
{id:"ts25",exam:"TEAS",section:"Science",q:"Red blood cells are produced in the:",o:["A. Spleen","B. Liver","C. Thymus","D. Red bone marrow"],a:"D",e:"Hematopoiesis (blood cell production) occurs in red bone marrow (in adults: flat bones like sternum, pelvis, ribs, vertebrae). Fetal hematopoiesis occurs in liver and spleen."},
{id:"ts26",exam:"TEAS",section:"Science",q:"The trachea divides into two primary bronchi at a landmark called the:",o:["A. Epiglottis","B. Carina","C. Hilum","D. Pleura"],a:"B",e:"The carina is the ridge at the bifurcation of the trachea into left and right primary bronchi (~T4 level). It is a key landmark — carina displacement on CXR can indicate mediastinal shift."},

// — Biology (13) —
{id:"ts27",exam:"TEAS",section:"Science",q:"Which organelle is the site of protein synthesis?",o:["A. Golgi apparatus","B. Mitochondria","C. Ribosome","D. Smooth ER"],a:"C",e:"Ribosomes translate mRNA into proteins. Found free in cytoplasm (for intracellular proteins) and on rough ER (for proteins destined for secretion or cell membrane)."},
{id:"ts28",exam:"TEAS",section:"Science",q:"During which phase of mitosis do chromosomes line up at the cell's equatorial plate?",o:["A. Prophase","B. Metaphase","C. Anaphase","D. Telophase"],a:"B",e:"PMAT: Prophase (condense), Metaphase (middle/equatorial plate), Anaphase (apart to poles), Telophase (two nuclei). Metaphase = Middle — easy memory hook."},
{id:"ts29",exam:"TEAS",section:"Science",q:"The process of transcription produces:",o:["A. DNA from RNA","B. Proteins from mRNA","C. mRNA from DNA","D. tRNA from proteins"],a:"C",e:"Transcription = DNA → mRNA (in nucleus). Translation = mRNA → protein (at ribosomes). 'Transcription' = transcribing the DNA code into mRNA."},
{id:"ts30",exam:"TEAS",section:"Science",q:"What is the function of the Golgi apparatus?",o:["A. Produce ATP","B. Store and digest cellular waste","C. Modify, package, and ship proteins","D. Produce mRNA"],a:"C",e:"Golgi apparatus = cellular 'post office.' Receives proteins from rough ER → modifies (glycosylation, etc.) → packages → ships to destinations (cell surface, lysosomes, secretion)."},
{id:"ts31",exam:"TEAS",section:"Science",q:"In a Punnett square, if one parent is Bb and the other is bb, what percentage of offspring will be carriers (Bb)?",o:["A. 0%","B. 25%","C. 50%","D. 100%"],a:"C",e:"Bb × bb: offspring = Bb, Bb, bb, bb. 50% Bb (carriers) and 50% bb (affected if recessive). This is a testcross — used to determine unknown genotype."},
{id:"ts32",exam:"TEAS",section:"Science",q:"What is osmosis?",o:["A. Movement of solutes from high to low concentration","B. Movement of water across a semipermeable membrane from low to high solute concentration","C. Active transport of ions using ATP","D. Diffusion of gases across a membrane"],a:"B",e:"Osmosis = passive movement of WATER (not solutes) across a semipermeable membrane from low solute (high water) to high solute (low water) concentration. No energy required."},
{id:"ts33",exam:"TEAS",section:"Science",q:"Which describes facilitated diffusion?",o:["A. Movement requiring ATP against a concentration gradient","B. Movement through protein channels down a concentration gradient without ATP","C. Bulk movement of large particles into a cell","D. Movement of water across a membrane"],a:"B",e:"Facilitated diffusion = passive transport (no ATP) DOWN a concentration gradient via protein carriers or channels (e.g., glucose transporters). Different from active transport (needs ATP, goes uphill)."},
{id:"ts34",exam:"TEAS",section:"Science",q:"Meiosis produces cells with how many chromosomes?",o:["A. 46 (diploid)","B. 92 (tetraploid)","C. 23 (haploid)","D. 12 (haploid)"],a:"C",e:"Meiosis reduces chromosome number by half → 23 chromosomes (haploid) in gametes. When sperm (23) + egg (23) fuse = 46 (diploid zygote). Meiosis occurs in gonads only."},
{id:"ts35",exam:"TEAS",section:"Science",q:"Which level of protein structure refers to the sequence of amino acids?",o:["A. Primary structure","B. Secondary structure","C. Tertiary structure","D. Quaternary structure"],a:"A",e:"Primary = amino acid sequence (determined by DNA). Secondary = alpha helices/beta sheets (hydrogen bonds). Tertiary = 3D folding. Quaternary = multiple polypeptide chains. Function depends on 3D shape."},
{id:"ts36",exam:"TEAS",section:"Science",q:"The Calvin cycle occurs in which part of the chloroplast?",o:["A. Thylakoid membrane","B. Stroma","C. Outer membrane","D. Granum"],a:"B",e:"Calvin cycle (light-independent reactions) = stroma of chloroplast. Light-dependent reactions (produce ATP/NADPH) = thylakoid membranes. Together they convert CO₂ to glucose."},
{id:"ts37",exam:"TEAS",section:"Science",q:"Which is an example of positive feedback in the body?",o:["A. Body temperature regulation by sweating","B. Blood glucose regulation by insulin","C. Childbirth contractions that intensify with increasing oxytocin","D. Blood pressure regulation by baroreceptors"],a:"C",e:"Positive feedback AMPLIFIES the response (rare in homeostasis). Oxytocin during labor → contractions → more oxytocin → stronger contractions → delivery. Most body feedback loops are NEGATIVE (corrective)."},
{id:"ts38",exam:"TEAS",section:"Science",q:"Bacteria reproduce primarily through:",o:["A. Meiosis","B. Mitosis","C. Binary fission","D. Budding"],a:"C",e:"Binary fission = bacteria split into two equal daughter cells. No nucleus involved (prokaryotes). Much faster than eukaryotic cell division — why bacteria can cause rapid infections."},
{id:"ts39",exam:"TEAS",section:"Science",q:"What are the three types of RNA and their functions? Choose the CORRECT match.",o:["A. mRNA=carries code, rRNA=brings amino acids, tRNA=makes ribosomes","B. mRNA=carries code, tRNA=brings amino acids, rRNA=ribosome structure","C. rRNA=carries code, mRNA=makes ribosomes, tRNA=brings amino acids","D. tRNA=carries code, mRNA=brings amino acids, rRNA=makes ribosomes"],a:"B",e:"mRNA (messenger) = carries genetic code from DNA to ribosome. tRNA (transfer) = carries specific amino acids. rRNA (ribosomal) = structural component of ribosomes. All three are needed for translation."},

// — Chemistry (12) —
{id:"ts40",exam:"TEAS",section:"Science",q:"What is the atomic number of carbon?",o:["A. 4","B. 6","C. 8","D. 12"],a:"B",e:"Carbon atomic number = 6 (6 protons). Atomic mass ≈ 12 (6 protons + 6 neutrons). Carbon is the backbone of all organic molecules. On the periodic table: C, period 2, group 14."},
{id:"ts41",exam:"TEAS",section:"Science",q:"A solution with a pH of 8.5 is classified as:",o:["A. Strongly acidic","B. Weakly acidic","C. Neutral","D. Basic/alkaline"],a:"D",e:"pH > 7 = basic/alkaline. pH < 7 = acidic. pH = 7 = neutral. 8.5 is above 7 = basic. Blood pH 7.35–7.45 is slightly basic. Acidosis = pH <7.35; Alkalosis = pH >7.45."},
{id:"ts42",exam:"TEAS",section:"Science",q:"Which macromolecule serves as the PRIMARY source of energy for the body?",o:["A. Proteins","B. Lipids","C. Carbohydrates","D. Nucleic acids"],a:"C",e:"Carbohydrates = primary/preferred energy source (4 kcal/g). Glucose → ATP via cellular respiration. Lipids (9 kcal/g) = secondary/reserve energy. Proteins used for energy only when carbs/fats are depleted."},
{id:"ts43",exam:"TEAS",section:"Science",q:"Which type of chemical reaction breaks complex molecules into simpler ones using water?",o:["A. Synthesis (dehydration)","B. Hydrolysis","C. Oxidation","D. Reduction"],a:"B",e:"Hydrolysis = splitting bonds using water (hydro=water, lysis=breaking). Digestion uses hydrolysis to break carbohydrates, proteins, and fats into absorbable units. Synthesis/dehydration = removes water to build molecules."},
{id:"ts44",exam:"TEAS",section:"Science",q:"Lipids (fats) are composed of:",o:["A. Amino acids","B. Nucleotides","C. Monosaccharides","D. Glycerol and fatty acids"],a:"D",e:"Triglycerides = 1 glycerol + 3 fatty acids. Fatty acids can be saturated (no double bonds) or unsaturated (1+ double bonds). Phospholipids = 2 fatty acids + glycerol + phosphate head (cell membrane)."},
{id:"ts45",exam:"TEAS",section:"Science",q:"The chemical formula for glucose is:",o:["A. C₆H₁₀O₅","B. C₆H₁₂O₆","C. C₁₂H₂₂O₁₁","D. CH₂O"],a:"B",e:"Glucose = C₆H₁₂O₆. The '6-6-6' rule: 6 carbons, 12 hydrogens, 6 oxygens. The main cellular fuel. C₁₂H₂₂O₁₁ = sucrose (table sugar, a disaccharide)."},
{id:"ts46",exam:"TEAS",section:"Science",q:"In the periodic table, elements in the same COLUMN (group) share:",o:["A. The same atomic mass","B. Similar chemical properties and the same number of valence electrons","C. The same number of neutrons","D. The same electron shell count"],a:"B",e:"Groups/families (vertical columns) = similar chemical behavior because they have the same number of valence electrons. Noble gases (group 18) all have full outer shells → non-reactive."},
{id:"ts47",exam:"TEAS",section:"Science",q:"Which statement about covalent bonds is TRUE?",o:["A. They form between a metal and nonmetal","B. They involve the transfer of electrons","C. They involve sharing of electron pairs","D. They produce ions"],a:"C",e:"Covalent bonds = electron sharing between nonmetal atoms. Ionic bonds = electron transfer (metal to nonmetal) → produce ions. Most bonds in biological molecules (C-H, O-H, N-H) are covalent."},
{id:"ts48",exam:"TEAS",section:"Science",q:"Proteins are polymers of:",o:["A. Monosaccharides","B. Fatty acids","C. Amino acids","D. Nucleotides"],a:"C",e:"Proteins = polymers of amino acids joined by peptide bonds. 20 different amino acids. Protein function depends on 3D shape. Enzymes, hormones (insulin), structural proteins (collagen) are all proteins."},
{id:"ts49",exam:"TEAS",section:"Science",q:"What is the difference between an atom and an ion?",o:["A. Atoms have protons; ions do not","B. Ions have an unequal number of protons and electrons (net charge)","C. Atoms have neutrons; ions do not","D. Ions are larger than atoms always"],a:"B",e:"Ion = atom that has gained or lost electrons → net charge. Cation (+) = lost electrons. Anion (−) = gained electrons. Example: Na⁺ (lost 1 e⁻), Cl⁻ (gained 1 e⁻). Electrolytes in blood are ions."},
{id:"ts50",exam:"TEAS",section:"Science",q:"In the equation: 2H₂ + O₂ → 2H₂O, what is being conserved?",o:["A. Temperature","B. Color","C. Mass (law of conservation of mass)","D. Pressure"],a:"C",e:"Law of conservation of mass: atoms are neither created nor destroyed in a chemical reaction — just rearranged. Left side: 4H + 2O. Right side: 4H + 2O. Mass is equal on both sides."},
{id:"ts51",exam:"TEAS",section:"Science",q:"An enzyme's ACTIVE SITE:",o:["A. Is the part of the enzyme that stores energy","B. Is the specific region that binds to the substrate","C. Produces the products of the reaction","D. Attracts electrons to the reaction"],a:"B",e:"Active site = specific 3D region of the enzyme that binds to its substrate (lock-and-key model). Substrate binds → enzyme-substrate complex forms → reaction proceeds → products released."},

// — Scientific Reasoning (14) —
{id:"ts52",exam:"TEAS",section:"Science",q:"A nurse observes that patients who receive 'get well' cards recover faster. To TEST this hypothesis scientifically, she should:",o:["A. Tell all patients to get cards","B. Survey nurses about their observations","C. Design a controlled experiment with a card group and a no-card control group","D. Review literature on positive thinking"],a:"C",e:"Scientific method: hypothesis → controlled experiment. A control group (no cards) and experimental group (cards) allow comparison. Variables must be controlled. Observation alone isn't sufficient."},
{id:"ts53",exam:"TEAS",section:"Science",q:"In a drug study, the control group receives a PLACEBO. The purpose of the placebo is to:",o:["A. Provide a second treatment option","B. Provide a baseline for comparison to isolate the drug's effect","C. Protect researchers from bias","D. Ensure all participants receive some benefit"],a:"B",e:"Placebo = inactive treatment given to control group. It controls for the placebo effect (psychological benefit of treatment). Comparing drug vs. placebo isolates the drug's actual pharmacological effect."},
{id:"ts54",exam:"TEAS",section:"Science",q:"A study shows that people who eat breakfast perform better on exams. This BEST demonstrates:",o:["A. Breakfast causes improved exam performance","B. A correlation between breakfast and exam performance","C. Students who eat breakfast are smarter","D. Skipping breakfast reduces IQ"],a:"B",e:"Observational/correlation studies show associations — NOT causation. To establish causation, a controlled experiment is needed. Correlation ≠ causation is a fundamental scientific principle."},
{id:"ts55",exam:"TEAS",section:"Science",q:"Which is the INDEPENDENT variable in an experiment?",o:["A. The measured outcome","B. The variable that is controlled and kept constant","C. The variable the researcher deliberately manipulates","D. The participant's background characteristics"],a:"C",e:"Independent variable (IV) = what the researcher changes/manipulates. Dependent variable (DV) = what is measured (the outcome). Controlled variables = kept constant to prevent confounding."},
{id:"ts56",exam:"TEAS",section:"Science",q:"A hypothesis must be:",o:["A. Proven true before testing","B. Testable and falsifiable","C. Based on personal opinion only","D. Already accepted as fact"],a:"B",e:"Scientific hypothesis: (1) testable — can be examined through experiment, (2) falsifiable — can be proven wrong. 'Ghosts exist' is not falsifiable. 'Drug X reduces fever' is testable/falsifiable."},
{id:"ts57",exam:"TEAS",section:"Science",q:"Which describes a CONTROLLED variable in an experiment?",o:["A. The variable being measured","B. The variable the researcher changes","C. Variables kept constant to prevent them from affecting results","D. The predicted outcome"],a:"C",e:"Controlled (constant) variables are held constant to ensure that changes in the DV are due to the IV only. Example: testing a drug — control: same dose, same time, same diet for all participants."},
{id:"ts58",exam:"TEAS",section:"Science",q:"Why is sample size important in a research study?",o:["A. A larger sample costs more money — always a negative","B. A larger sample increases statistical reliability and reduces the effect of outliers","C. Sample size only matters in animal studies","D. Smaller samples are always more accurate"],a:"B",e:"Larger sample = more reliable, generalizable results. Small samples = higher chance that results are due to random variation. Sample size calculations determine how many subjects are needed for statistical power."},
{id:"ts59",exam:"TEAS",section:"Science",q:"A nurse conducts an experiment without a control group. The major problem with this design is:",o:["A. The results will always be positive","B. There is no baseline for comparison to determine if the treatment caused the observed change","C. The experiment cannot be published","D. The patients won't cooperate"],a:"B",e:"Without a control group, you can't know if observed changes are due to the treatment or other factors (time, placebo effect, natural recovery). Controls are essential for valid causal conclusions."},
{id:"ts60",exam:"TEAS",section:"Science",q:"Which represents a QUALITATIVE observation?",o:["A. Body temperature is 101.4°F","B. Blood pressure is 140/90 mmHg","C. The patient appears anxious and restless","D. Hemoglobin is 9.2 g/dL"],a:"C",e:"Qualitative = descriptive, non-numerical observations. 'Appears anxious and restless' = observable behavior. Quantitative = measurable with numbers (temp, BP, lab values). Both are valid in clinical assessment."},
{id:"ts61",exam:"TEAS",section:"Science",q:"In scientific notation, 0.0025 is expressed as:",o:["A. 2.5 × 10²","B. 2.5 × 10⁻³","C. 2.5 × 10⁻⁴","D. 25 × 10⁻⁴"],a:"B",e:"0.0025 → move decimal right 3 places → 2.5 × 10⁻³. Negative exponent = number <1. Scientific notation is used in microbiology (bacterial counts) and chemistry (concentrations)."},
{id:"ts62",exam:"TEAS",section:"Science",q:"A researcher publishes a study showing Drug X works, but doesn't publish two earlier studies showing it didn't. This is an example of:",o:["A. Random sampling error","B. Publication bias","C. Selection bias","D. Confounding"],a:"B",e:"Publication bias = tendency to publish positive results while filing away negative results. This skews the literature and can lead clinicians to overestimate a drug's effectiveness. Systematic reviews try to find all studies."},
{id:"ts63",exam:"TEAS",section:"Science",q:"The DEPENDENT variable in 'Does exercise reduce blood pressure?' is:",o:["A. The type of exercise","B. The frequency of exercise","C. Blood pressure (the measured outcome)","D. The age of participants"],a:"C",e:"DV = what is measured (blood pressure). IV = exercise (what is manipulated). Age, diet, medications = controlled variables (must be held constant). Always ask: what are we measuring?"},
{id:"ts64",exam:"TEAS",section:"Science",q:"Which is the correct order of the scientific method?",o:["A. Hypothesis → Observation → Experiment → Analysis → Conclusion","B. Experiment → Hypothesis → Observation → Conclusion → Analysis","C. Observation → Question → Hypothesis → Experiment → Analysis → Conclusion","D. Question → Experiment → Observation → Hypothesis → Analysis"],a:"C",e:"Scientific method: (1) Observation, (2) Question, (3) Hypothesis (educated prediction), (4) Experiment, (5) Data analysis, (6) Conclusion, (7) Communication/peer review. OQHEACC."},
{id:"ts65",exam:"TEAS",section:"Science",q:"What does a p-value of 0.03 indicate in a clinical study?",o:["A. 3% of the sample improved","B. There is a 3% probability the results are due to chance","C. The study had 3 confounding variables","D. 97% of participants responded to treatment"],a:"B",e:"P-value = probability results occurred by chance. p=0.03 means 3% chance results are random → statistically significant (below p<0.05 threshold). Lower p-value = stronger evidence against the null hypothesis."},

// ═══════════════════════════════════════════════
// ENGLISH & LANGUAGE USAGE — 38 questions
// Sub-areas: Conventions of Standard English (14), Knowledge of Language (13), Vocabulary (11)
// ═══════════════════════════════════════════════

// — Conventions of Standard English (14) —
{id:"te1",exam:"TEAS",section:"English",q:"Which sentence uses a comma CORRECTLY?",o:["A. The nurse assessed the patient, and documented the findings","B. Although tired, the nurse completed all her charting","C. The medication was given, to reduce inflammation","D. She called the doctor, because the BP was low"],a:"B",e:"Use a comma after an introductory dependent clause (before the main clause). 'Although tired' is an introductory clause → comma before 'the nurse.' Don't put a comma between subject and verb (A, C, D)."},
{id:"te2",exam:"TEAS",section:"English",q:"Identify the COMPLETE subject in: 'The experienced charge nurse reviewed the incident report carefully.'",o:["A. charge nurse","B. The experienced charge nurse","C. reviewed","D. carefully"],a:"B",e:"Complete subject = the noun phrase including all modifiers. 'The experienced charge nurse' (article + adjective + noun). Simple subject = nurse. Predicate = reviewed the report carefully."},
{id:"te3",exam:"TEAS",section:"English",q:"Which option correctly uses an APOSTROPHE?",o:["A. The patients' rights must be respected (referring to multiple patients)","B. The nurses station is on the right","C. The medication's were locked in the Pyxis","D. It's important to wash you're hands"],a:"A",e:"patients' = plural possessive (rights belonging to multiple patients — apostrophe after the 's'). Option B needs an apostrophe (nurse's or nurses'). C adds unnecessary apostrophe. D misuses it's/your."},
{id:"te4",exam:"TEAS",section:"English",q:"Which word is spelled CORRECTLY?",o:["A. Seperate","B. Accomodate","C. Pharmacuetical","D. Pharmaceutical"],a:"D",e:"Pharmaceutical: ph-ar-ma-ceu-ti-cal. Common misspellings: separate (not seperate), accommodate (2 c's, 2 m's), pharmaceutical (not pharmacuetical)."},
{id:"te5",exam:"TEAS",section:"English",q:"Choose the correct verb form: 'Neither the nurses nor the physician ___ available.'",o:["A. are","B. were","C. is","D. have been"],a:"C",e:"With 'neither/nor' and 'either/or,' the verb agrees with the NEAREST subject. Nearest subject = 'physician' (singular) → 'is.' If 'physicians' (plural) were nearest: 'are.'"},
{id:"te6",exam:"TEAS",section:"English",q:"Which sentence is grammatically correct?",o:["A. Me and my colleague attended the training","B. My colleague and I attended the training","C. My colleague and me attended the training","D. Myself and my colleague attended the training"],a:"B",e:"Subject pronouns (I, he, she, we, they) perform the action. Object pronouns (me, him, her, us) receive it. 'My colleague and I' = subject → correct. Test: remove 'my colleague and' → 'I attended' (not 'me attended')."},
{id:"te7",exam:"TEAS",section:"English",q:"A RUN-ON sentence is best corrected by:",o:["A. Adding more adjectives","B. Removing the subject","C. Adding a period, semicolon, or coordinating conjunction between independent clauses","D. Making both clauses dependent"],a:"C",e:"Run-on = two independent clauses joined without proper punctuation. Fix: (1) period + new sentence, (2) semicolon, (3) comma + FANBOYS conjunction, or (4) make one clause dependent."},
{id:"te8",exam:"TEAS",section:"English",q:"Which sentence contains PARALLEL STRUCTURE?",o:["A. The nurse likes assessing patients, to document, and medication administration","B. The nurse likes assessing patients, documenting findings, and administering medications","C. The nurse likes to assess, documenting findings, and administer medications","D. The nurse likes assessment, to document, and administers medications"],a:"B",e:"Parallel structure = all items in a series use the same grammatical form. All gerunds (-ing): assessing, documenting, administering = parallel. Mixing infinitives and gerunds breaks parallelism."},
{id:"te9",exam:"TEAS",section:"English",q:"The sentence 'The patient's condition improved.' is in which voice?",o:["A. Passive voice","B. Active voice","C. Future perfect tense","D. Subjunctive mood"],a:"B",e:"Active voice: subject (patient's condition) performs the action (improved). Passive: 'The patient's condition was improved by treatment.' Active voice is clearer and preferred in most writing."},
{id:"te10",exam:"TEAS",section:"English",q:"Which option CORRECTLY uses a semicolon?",o:["A. The patient refused surgery; but she agreed to physical therapy","B. The patient was stable; however, monitoring continued","C. The nurse documented; the findings","D. After assessment; the nurse reported to the physician"],a:"B",e:"Semicolons join two related independent clauses. Option B: 'The patient was stable' + 'monitoring continued' — two complete clauses. 'However' after semicolon is correct. A misuses semicolon with 'but' (use comma instead)."},
{id:"te11",exam:"TEAS",section:"English",q:"'The medication was prescribed; the patient refused to take it.' This sentence demonstrates:",o:["A. Cause and effect only","B. Two related independent clauses joined by a semicolon","C. A run-on sentence","D. A dependent clause followed by an independent clause"],a:"B",e:"Semicolon correctly joins two related independent clauses (each has subject + verb, expresses complete thought, and they're related). The semicolon signals the contrast without needing a conjunction."},
{id:"te12",exam:"TEAS",section:"English",q:"Which is a SENTENCE FRAGMENT?",o:["A. The patient ambulated in the hallway","B. After receiving the preoperative medication","C. The nurse assessed and documented","D. Vital signs were within normal limits"],a:"B",e:"Fragment = incomplete sentence. 'After receiving the preoperative medication' is a subordinate clause — it has no independent clause to complete the thought. A, C, D are all complete sentences."},
{id:"te13",exam:"TEAS",section:"English",q:"In which sentence does the pronoun AGREE with its antecedent?",o:["A. Each nurse must submit their timesheet by Friday","B. All nurses must submit her timesheet by Friday","C. Each nurse must submit her timesheet by Friday","D. Every nurses must submit their timesheet"],a:"C",e:"'Each nurse' = singular → singular pronoun. Traditionally: 'her' or 'his.' Modern usage accepts 'their' with singular 'each' (A is increasingly accepted). However, for TEAS: singular 'each' → singular pronoun = C."},
{id:"te14",exam:"TEAS",section:"English",q:"Which sentence avoids double negatives?",o:["A. The patient didn't take no medication","B. She couldn't find nobody to help","C. There were no adverse reactions to the medication","D. The nurse didn't have no documentation"],a:"C",e:"Double negatives = two negative words in one clause (didn't + no, couldn't + nobody). They make a positive statement unintentionally. 'There were no adverse reactions' uses only one negative = correct."},

// — Knowledge of Language (13) —
{id:"te15",exam:"TEAS",section:"English",q:"Which transition word would BEST connect these sentences: 'The patient was in pain. ___, she refused opioid medication.'",o:["A. Therefore","B. Furthermore","C. Nevertheless","D. Similarly"],a:"C",e:"'Nevertheless' = despite that, even so — signals contrast (she was in pain BUT refused opioids). 'Therefore' = result. 'Furthermore' = addition. 'Similarly' = comparison. The contrast needs a contrast word."},
{id:"te16",exam:"TEAS",section:"English",q:"The MOST formal writing style would be appropriate in:",o:["A. A text message to a colleague","B. A personal nursing journal","C. A peer-reviewed research proposal","D. A social media post about nursing"],a:"C",e:"Formal writing: no contractions, technical vocabulary, third-person, objective tone. Used in academic papers, research proposals, official reports. Informal writing for casual communication (texts, social media)."},
{id:"te17",exam:"TEAS",section:"English",q:"Which represents the MOST precise word choice in clinical documentation?",o:["A. 'Patient seemed kind of dizzy'","B. 'Patient was a little out of it'","C. 'Patient reported dizziness rated 7/10 with sudden position changes'","D. 'Patient was not feeling well and had dizziness'"],a:"C",e:"Clinical documentation requires specificity: severity (7/10), quality (dizziness), and trigger (position changes). Vague terms ('kind of,' 'a little,' 'not feeling well') are unacceptable in medical records."},
{id:"te18",exam:"TEAS",section:"English",q:"'Aseptic technique' and 'antiseptic solution' — what is the relationship of 'aseptic' and 'antiseptic'?",o:["A. They are synonyms with identical meanings","B. They are antonyms","C. They are related terms with different meanings and uses","D. They are interchangeable in clinical settings"],a:"C",e:"Aseptic = free from contamination (aseptic technique = sterile procedure). Antiseptic = substance that kills microorganisms on living tissue. Related but distinct clinical concepts."},
{id:"te19",exam:"TEAS",section:"English",q:"Which word has a POSITIVE connotation in a healthcare context?",o:["A. Noncompliant","B. Difficult","C. Engaged in care","D. Demanding"],a:"C",e:"'Engaged in care' is patient-centered, positive language. 'Noncompliant' and 'difficult' are judgmental, negative. Person-first, strengths-based language in healthcare reflects respect and reduces stigma."},
{id:"te20",exam:"TEAS",section:"English",q:"Which sentence is written in ACTIVE VOICE?",o:["A. The medications were administered by the nurse","B. The chart was reviewed by the physician","C. The nurse administered the medications on time","D. Vital signs are recorded every 4 hours by the CNA"],a:"C",e:"Active voice: subject (nurse) performs the action (administered). In passive voice, the subject receives the action. Active voice is clearer, more direct, and preferred in most writing and documentation."},
{id:"te21",exam:"TEAS",section:"English",q:"Which word BEST replaces the underlined word for clarity: 'The nurse got the information from the patient.'",o:["A. Acquired","B. Took","C. Obtained","D. Grabbed"],a:"C",e:"'Obtained' is the most precise clinical term for gathering information in a professional context. 'Acquired' is acceptable. 'Took' and 'grabbed' are informal/imprecise. Word precision improves documentation clarity."},
{id:"te22",exam:"TEAS",section:"English",q:"When should a writer use 'affect' versus 'effect'?",o:["A. 'Affect' is a noun; 'effect' is a verb","B. They are interchangeable in all contexts","C. 'Affect' is typically a verb (to influence); 'effect' is typically a noun (result/outcome)","D. 'Affect' is used only in psychology"],a:"C",e:"AFFECT (verb): 'Stress affects healing.' EFFECT (noun): 'Stress has a negative effect on healing.' Memory: RAVEN — Remember, Affect = Verb, Effect = Noun. Exception: 'to effect change' (rare verb use of effect)."},
{id:"te23",exam:"TEAS",section:"English",q:"What is the purpose of a THESIS STATEMENT in a persuasive essay?",o:["A. To summarize all evidence in the essay","B. To provide the central argument the essay will support","C. To introduce the topic without taking a position","D. To list all sources used in the essay"],a:"B",e:"Thesis statement = the writer's central claim or argument. It tells the reader the main point and what the essay will prove. It appears in the introduction and is supported throughout the essay."},
{id:"te24",exam:"TEAS",section:"English",q:"Which option BEST demonstrates concise writing?",o:["A. 'Due to the fact that the patient was experiencing pain, medication was administered'","B. 'Because the patient was in pain, medication was given'","C. 'In light of the existing pain situation that the patient presented with, medication administration occurred'","D. 'In the event that pain was present, medication was provided to the patient'"],a:"B",e:"Concise writing eliminates wordiness. 'Because the patient was in pain, medication was given' = same meaning in fewer words. Avoid wordy phrases: 'due to the fact that' → 'because.'"},
{id:"te25",exam:"TEAS",section:"English",q:"Which is an example of DEDUCTIVE reasoning?",o:["A. I observed 5 patients improve with treatment X, so it probably works","B. All patients with fever over 103°F require assessment. This patient has a 104°F fever. Therefore, this patient requires assessment.","C. I think this patient is anxious based on my past experience","D. Most nurses prefer day shift, so nursing is better during the day"],a:"B",e:"Deductive reasoning = general principle → specific conclusion (top-down). All A are B; this is A; therefore this is B. Inductive reasoning = specific observations → general conclusion (bottom-up, like option A)."},
{id:"te26",exam:"TEAS",section:"English",q:"The Latin abbreviation 'e.g.' means:",o:["A. That is","B. For example","C. And others","D. Namely"],a:"B",e:"e.g. = exempli gratia = for example. i.e. = id est = that is. et al. = et alii = and others. etc. = et cetera = and so forth. These appear in academic and clinical writing."},
{id:"te27",exam:"TEAS",section:"English",q:"Which sentence uses FIGURATIVE LANGUAGE?",o:["A. The patient had a temperature of 103°F","B. The nurse administered 10 mg of morphine","C. The ICU was a war zone last night","D. The patient was admitted at 2200 hours"],a:"C",e:"'War zone' = metaphor — comparing the ICU to a war zone figuratively. Options A, B, and D are literal, factual statements with no figurative meaning. Figurative language = non-literal, creative expression."},

// — Vocabulary (11) —
{id:"te28",exam:"TEAS",section:"English",q:"The word BENEVOLENT most nearly means:",o:["A. Hostile","B. Indifferent","C. Charitable and kind","D. Demanding and strict"],a:"C",e:"Benevolent = well-meaning, kind, charitable. Malevolent = opposite (wishing harm). Root: bene- (good/well) + volent (wishing). Benevolence is a core value in nursing practice."},
{id:"te29",exam:"TEAS",section:"English",q:"In the word 'UNHELPFUL,' what is the BASE WORD?",o:["A. un-","B. help","C. -ful","D. helpful"],a:"B",e:"Base/root word = the core meaning unit. 'Help' = base word. 'Un-' = prefix (not). '-ful' = suffix (full of). Un + help + ful = not full of help. Prefixes and suffixes modify but don't constitute the base."},
{id:"te30",exam:"TEAS",section:"English",q:"The prefix 'SUPER-' most likely means:",o:["A. Below","B. Before","C. Above or beyond","D. Against"],a:"C",e:"Super- = above/beyond. Superficial = above the surface. Superior = above/better. Superinfection = infection on top of another. Compare: sub- (below), pre- (before), anti- (against)."},
{id:"te31",exam:"TEAS",section:"English",q:"'Ubiquitous' most nearly means:",o:["A. Rare and difficult to find","B. Present everywhere or very frequently encountered","C. Unique and unusual","D. Dangerous and toxic"],a:"B",e:"Ubiquitous = seeming to be everywhere at once. 'Smartphones are ubiquitous in modern life.' From Latin ubique = everywhere. Opposite: rare, scarce."},
{id:"te32",exam:"TEAS",section:"English",q:"Which word is an ANTONYM for 'malignant'?",o:["A. Cancerous","B. Aggressive","C. Benign","D. Metastatic"],a:"C",e:"Malignant = cancerous/harmful (tends to spread). Benign = harmless/noncancerous. These are the core antonyms in oncology. Metastatic = spread to distant sites (describes malignant behavior)."},
{id:"te33",exam:"TEAS",section:"English",q:"The suffix '-OLOGY' appears in cardiology, neurology, and oncology. It means:",o:["A. Surgical removal","B. Disease condition","C. Study or science of","D. Inflammation of"],a:"C",e:"-ology = study/science of. Cardiology = study of the heart. Neurology = study of nerves. Oncology = study of cancer. The -ologist = the specialist. -itis = inflammation. -ectomy = removal."},
{id:"te34",exam:"TEAS",section:"English",q:"What does 'CIRCUMSPECT' mean?",o:["A. Acting hastily without thinking","B. Wary and cautious; considering all circumstances","C. Overconfident in one's abilities","D. Circular in shape"],a:"B",e:"Circumspect = thinking carefully before acting; cautious. Roots: circum- (around) + spect (look) = looking around (all directions) before deciding. A circumspect nurse considers all risks before a procedure."},
{id:"te35",exam:"TEAS",section:"English",q:"'Ameliorate' most nearly means:",o:["A. Worsen","B. Improve or make better","C. Eliminate","D. Evaluate"],a:"B",e:"Ameliorate = to make better or improve a bad situation. 'The treatment ameliorated the patient's symptoms.' Opposite: exacerbate (worsen). Used in clinical literature for interventions that improve outcomes."},
{id:"te36",exam:"TEAS",section:"English",q:"The word 'VIABLE' most nearly means:",o:["A. Unworkable","B. Capable of surviving or succeeding","C. Harmful","D. Temporary"],a:"B",e:"Viable = capable of surviving/working. A viable treatment option = one that can work. A viable premature infant = capable of survival outside the womb. Non-viable = cannot survive."},
{id:"te37",exam:"TEAS",section:"English",q:"What does the prefix 'INTER-' mean?",o:["A. Within","B. Between or among","C. Before","D. After"],a:"B",e:"Inter- = between/among. Interpersonal = between people. Interdisciplinary = among disciplines. Compare: intra- = within (intravascular = within a vessel). Don't confuse inter- and intra-."},
{id:"te38",exam:"TEAS",section:"English",q:"'Empirical evidence' refers to:",o:["A. Evidence based on theory alone","B. Evidence based on observation, experiment, and direct experience","C. Evidence from expert consensus only","D. Evidence published in textbooks"],a:"B",e:"Empirical = based on observation/experiment (from Greek empeiria = experience). Empirical evidence is the foundation of science and EBP. Opposite: anecdotal (personal stories) or theoretical (not yet tested)."},
];

